function feeOiHistory(){const out=[];for(const p of SERIES){const rev=Math.max(0,p.v-cumAt(addDays(p.d,-30)));const oi=oiAt(p.d);if(rev>0&&oi)out.push({d:p.d,rev,oi,yield:(rev/30*365)/oi*100});}return out;}

