function tzParts(date,tz=RESET_TZ.tz){
  const parts=new Intl.DateTimeFormat('en-US',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit',
    hour:'2-digit',minute:'2-digit',second:'2-digit',hourCycle:'h23'}).formatToParts(date);
  return Object.fromEntries(parts.filter(p=>p.type!=='literal').map(p=>[p.type,p.value]));
}
const resetDateKey=(date=new Date())=>{const p=tzParts(date);return `${p.year}-${p.month}-${p.day}`;};
function tzOffsetMinutes(date,tz=RESET_TZ.tz){
  const p=tzParts(date,tz);
  const asUTC=Date.UTC(+p.year,+p.month-1,+p.day,+p.hour,+p.minute,+p.second);
  return Math.round((asUTC-date.getTime())/60000);
}
function resetMidnightTs(d){
  const [y,m,day]=d.split('-').map(Number);
  let utc=Date.UTC(y,m-1,day,0,0,0);
  for(let i=0;i<3;i++)utc=Date.UTC(y,m-1,day,0,0,0)-tzOffsetMinutes(new Date(utc))*60000;
  return Math.floor(utc/1000);
}
const resetTimeString=(date=new Date())=>date.toLocaleTimeString('en-US',{timeZone:RESET_TZ.tz,hour12:false});
const resetTimeShort=(date=new Date())=>date.toLocaleTimeString('en-US',{timeZone:RESET_TZ.tz,hour:'2-digit',minute:'2-digit',second:'2-digit',hourCycle:'h23'});
const resetMonthName=ym=>new Date(resetMidnightTs(ym+'-01')*1000).toLocaleDateString('en-US',{month:'short',year:'numeric',timeZone:RESET_TZ.tz});
const resetWeekday=d=>new Date(resetMidnightTs(d)*1000).toLocaleDateString('en-US',{weekday:'short',timeZone:RESET_TZ.tz});
function resetLocalTs(d,h=0,m=0,s=0){
  const [y,mo,day]=d.split('-').map(Number);
  let utc=Date.UTC(y,mo-1,day,h,m,s);
  for(let i=0;i<3;i++)utc=Date.UTC(y,mo-1,day,h,m,s)-tzOffsetMinutes(new Date(utc))*60000;
  return Math.floor(utc/1000);
}
function resetHourParts(date=new Date()){
  const p=tzParts(date);
  return {date:`${p.year}-${p.month}-${p.day}`,hour:+p.hour};
}
const resetHourKey=(date=new Date())=>{const p=resetHourParts(date);return `${p.date}T${String(p.hour).padStart(2,'0')}`;};
const resetHourLabel=h=>`${String(h).padStart(2,'0')}:00-${String((h+1)%24).padStart(2,'0')}:00 ET`;
function hourRangeLabel(date,h,tz,label){
  const start=new Date(resetLocalTs(date,h)*1000);
  const end=new Date(resetLocalTs(date,h+1)*1000);
  const opt={timeZone:tz,hour:'2-digit',minute:'2-digit',hourCycle:'h23'};
  const s=start.toLocaleTimeString('en-US',opt), e=end.toLocaleTimeString('en-US',opt);
  const day=start.toLocaleDateString('en-US',{timeZone:tz,weekday:'short'});
  return `${s}-${e} ${label} · ${day}`;
}
function localSessionCell(date,h,c){
  const start=new Date(resetLocalTs(date,h)*1000);
  const end=new Date(resetLocalTs(date,h+1)*1000);
  const opt={timeZone:c.tz,hour:'2-digit',minute:'2-digit',hourCycle:'h23'};
  const s=start.toLocaleTimeString('en-US',opt), e=end.toLocaleTimeString('en-US',opt);
  const day=start.toLocaleDateString('en-US',{timeZone:c.tz,weekday:'short'});
  const hr=+tzParts(start,c.tz).hour;
  const daytime=hr>=9&&hr<18;
  return `<span class="tlog-country ${daytime?'day':''}"><b>${c.flag}</b>${s}-${e}${daytime?'<small>DAY</small>':''}<em>${day}</em></span>`;
}
function compactHourRange(date,h,tz,label){
  const start=new Date(resetLocalTs(date,h)*1000);
  const end=new Date(resetLocalTs(date,h+1)*1000);
  const opt={timeZone:tz,hour:'2-digit',minute:'2-digit',hourCycle:'h23'};
  return `${start.toLocaleTimeString('en-US',opt)}-${end.toLocaleTimeString('en-US',opt)} ${label}`;
}
