function sumEarn(start,end){
  let sum=0,seen=false;
  dailyEarn().forEach(x=>{if(x.d>=start&&x.d<=end){sum+=x.e;seen=true;}});
  return seen?sum:null;
}
function shiftMonth(dstr,delta){
  const dt=new Date(dstr+'T00:00:00Z');
  const day=dt.getUTCDate();
  dt.setUTCMonth(dt.getUTCMonth()+delta,1);
  const last=new Date(Date.UTC(dt.getUTCFullYear(),dt.getUTCMonth()+1,0)).getUTCDate();
  dt.setUTCDate(Math.min(day,last));
  return dt.toISOString().slice(0,10);
}
function shiftYear(dstr,delta){
  const dt=new Date(dstr+'T00:00:00Z');
  dt.setUTCFullYear(dt.getUTCFullYear()+delta);
  return dt.toISOString().slice(0,10);
}
