/* ---------- implied valuation: OI -> circulating market-cap power-law model ----------
   Peer perp-DEX tokens (OI vs circulating mcap); fit MCAP = A * OI^B by log-least-squares.
   A/B reproduce the Perpetual Pulse "Circulating MarketCap vs OI" model (R^2~0.74, log-log). */
const VAL_FIT={A:10.0339,B:0.8753,r2:0.74};
const VAL_FLOAT=0.25; // assumed circulating float at TGE, for FDV
let VAL_MCAP_ASOF='CoinGecko snapshot · 2026-07-10 16:55 SGT';
const VAL_COMPS=[
  {n:'Hyperliquid',cg:'hyperliquid',oi:10650289066,mc:15251711817,big:1},
  {n:'Aster',cg:'aster-2',oi:1873558499,mc:1694156746,big:1},
  {n:'Lighter',cg:'lighter',oi:841224409,mc:617506501,big:1},
  {n:'Jupiter',cg:'jupiter-exchange-solana',oi:231885286,mc:696647498,big:1},
  {n:'edgeX',cg:'edgex',oi:297961154,mc:143319946},
  {n:'dYdX',cg:'dydx-chain',oi:39069154,mc:113579140},
  {n:'GMX',cg:'gmx',oi:45194812,mc:64586151},
  {n:'ApeX Protocol',cg:'apex-token-2',oi:113429724,mc:38384644},
  {n:'Avantis',cg:'avantis',oi:12551268,mc:31220697},
  {n:'Orderly',cg:'orderly-network',oi:35976834,mc:13370390},
  {n:'Gains Network',cg:'gains-network',oi:3337198,mc:14535752},
  {n:'Drift',cg:'drift-protocol',oi:123964778,mc:9022464}
];
const valPred=oi=>VAL_FIT.A*Math.pow(oi,VAL_FIT.B);
function fmtBig(v){return v>=1e9?'$'+(v/1e9).toFixed(2)+'B':v>=1e6?'$'+(v/1e6).toFixed(0)+'M':'$'+fmtK(v);}
function renderValuation(){
  const svg=$('#valScatter'); if(!svg)return;
  VAL_COMPS.forEach(c=>{
    const livePeer=PEERS.list.find(p=>p.n===c.n);
    if(livePeer&&livePeer.oi>0)c.oi=livePeer.oi;
  });
  const va=PEERS.list.find(p=>p.me);
  const oi=va&&va.oi>0?va.oi:1210288593;
  const mcap=valPred(oi), fdv=mcap/VAL_FLOAT;
  const hlComp=VAL_COMPS.find(c=>c.n==='Hyperliquid');
  const hlVsVar=hlComp&&mcap>0?hlComp.mc/mcap:0;
  const varBelowHl=hlComp&&hlComp.mc>0?(1-mcap/hlComp.mc)*100:0;
  $('#valMcap')&&($('#valMcap').textContent=fmtBig(mcap));
  $('#valVsHl')&&($('#valVsHl').textContent=hlVsVar.toFixed(1)+'x');
  $('#valVsHlSub')&&($('#valVsHlSub').innerHTML=`Hyperliquid is <b>${hlVsVar.toFixed(1)}x larger</b>. Variational implied is <b>${varBelowHl.toFixed(1)}% below</b> its current ${fmtBig(hlComp.mc)} market cap.`);
  $('#valOiBase')&&($('#valOiBase').textContent=fmtBig(oi)+(PEERS.live?' live':''));
  $('#valFdv')&&($('#valFdv').textContent=fmtBig(fdv));
  $('#valFloat')&&($('#valFloat').textContent=Math.round(VAL_FLOAT*100)+'%');
  $('#valFdvRange')&&($('#valFdvRange').textContent=fmtBig(mcap/0.33)+' - '+fmtBig(mcap/0.20));
  const W=760,H=430,pl=58,pr=18,pt=22,pb=44;
  const lx0=Math.log10(2e6),lx1=Math.log10(2.2e10),ly0=Math.log10(4e6),ly1=Math.log10(2.2e10);
  const X=v=>pl+(Math.log10(v)-lx0)/(lx1-lx0)*(W-pl-pr);
  const Y=v=>pt+(1-(Math.log10(v)-ly0)/(ly1-ly0))*(H-pt-pb);
  const lbl=v=>v>=1e9?'$'+(v/1e9)+'B':'$'+(v/1e6)+'M';
  const ticks=[1e7,1e8,1e9,1e10];
  let grid='';
  ticks.forEach(t=>{const x=X(t);
    grid+=`<line x1="${x.toFixed(1)}" y1="${pt}" x2="${x.toFixed(1)}" y2="${H-pb}" stroke="rgba(85,184,255,.08)"/>`+
      `<text x="${x.toFixed(1)}" y="${H-pb+16}" fill="#4a5674" font-size="10" text-anchor="middle">${lbl(t)}</text>`;});
  ticks.forEach(t=>{const y=Y(t);
    grid+=`<line x1="${pl}" y1="${y.toFixed(1)}" x2="${W-pr}" y2="${y.toFixed(1)}" stroke="rgba(85,184,255,.08)"/>`+
      `<text x="${pl-8}" y="${(y+3).toFixed(1)}" fill="#4a5674" font-size="10" text-anchor="end">${lbl(t)}</text>`;});
  grid+=`<text x="${((pl+(W-pr))/2).toFixed(0)}" y="${H-4}" fill="#6b83a8" font-size="10" text-anchor="middle" letter-spacing="1.5">OPEN INTEREST →</text>`;
  const midY=((pt+(H-pb))/2).toFixed(1);
  grid+=`<text x="14" y="${midY}" fill="#6b83a8" font-size="10" text-anchor="middle" letter-spacing="1.5" transform="rotate(-90 14 ${midY})">CIRCULATING MCAP →</text>`;
  let path='';
  for(let lx=lx0;lx<=lx1+1e-9;lx+=(lx1-lx0)/60){const oiv=Math.pow(10,lx);const x=X(oiv),y=Y(valPred(oiv));path+=(path?'L':'M')+x.toFixed(1)+' '+y.toFixed(1)+' ';}
  const trend=`<path d="${path}" fill="none" stroke="url(#valTrend)" stroke-width="2.4" opacity=".9"/>`;
  const premCol=p=>p>=1.08?'#c7f284':p<=0.92?'#f08aa0':'#72cdf7';
  // Clear legend: the line is the model's fair-value estimate.
  let legend=`<g transform="translate(${pl+8},${pt+10})" font-family="var(--mono)">`+
    `<circle cx="4" cy="0" r="3.8" fill="#c7f284"/><text x="13" y="3.8" fill="#b7c9df" font-size="10" font-weight="800">PREMIUM: market cap above model</text>`+
    `<circle cx="4" cy="17" r="3.8" fill="#e0728a"/><text x="13" y="20.8" fill="#b7c9df" font-size="10" font-weight="800">DISCOUNT: market cap below model</text></g>`;
  let dots='';
  VAL_COMPS.forEach(c=>{if(c.oi<=0||c.mc<=0)return;
    const imp=valPred(c.oi), prem=c.mc/imp, col=premCol(prem);
    const x=X(c.oi), ya=Y(c.mc), yi=Y(imp), logo=PLOGO[c.n], s=20;
    dots+=`<line x1="${x.toFixed(1)}" y1="${yi.toFixed(1)}" x2="${x.toFixed(1)}" y2="${ya.toFixed(1)}" stroke="${col}" stroke-width="1.3" stroke-dasharray="2 2" opacity=".5"/>`;
    if(logo){
      dots+=`<rect x="${(x-s/2).toFixed(1)}" y="${(ya-s/2).toFixed(1)}" width="${s}" height="${s}" rx="6" fill="#0a1220" stroke="${col}" stroke-width="1.5"/>`+
        `<image href="${logo}" x="${(x-s/2+3).toFixed(1)}" y="${(ya-s/2+3).toFixed(1)}" width="${(s-6)}" height="${(s-6)}" preserveAspectRatio="xMidYMid meet"/>`;
    }else{
      dots+=`<circle cx="${x.toFixed(1)}" cy="${ya.toFixed(1)}" r="5" fill="${col}" stroke="#0a1220" stroke-width="1"/>`+
        `<text x="${x.toFixed(1)}" y="${(ya-9).toFixed(1)}" fill="#9db6da" font-size="8.5" text-anchor="middle">${c.n}</text>`;
    }
    if(c.n==='Hyperliquid'){
      const callX=Math.max(pl+180,x-142),callY=Math.min(H-pb-38,ya+18);
      const word=prem>=1?'PREMIUM':'DISCOUNT';
      dots+=`<line x1="${(x-3).toFixed(1)}" y1="${(ya+8).toFixed(1)}" x2="${(callX+126).toFixed(1)}" y2="${(callY+4).toFixed(1)}" stroke="${col}" stroke-width="1" opacity=".75"/>`+
        `<g transform="translate(${callX.toFixed(1)},${callY.toFixed(1)})"><rect x="0" y="0" width="130" height="34" rx="7" fill="#07111d" stroke="${col}" stroke-width="1.2"/>`+
        `<text x="8" y="13" fill="${col}" font-size="9.5" font-weight="900">HL ${word} ${prem>=1?'+':''}${((prem-1)*100).toFixed(0)}%</text>`+
        `<text x="8" y="26" fill="#b7c9df" font-size="9">${prem.toFixed(2)}x model value</text></g>`;
    }});
  const vx=X(oi),vy=Y(mcap),vs=20;
  const cxL=Math.min(vx+20,W-pr-108).toFixed(1), cyL=Math.max(vy-50,pt+14).toFixed(1);
  const vlogo=PLOGO['Variational'];
  const hero=`<circle cx="${vx.toFixed(1)}" cy="${vy.toFixed(1)}" r="14" fill="rgba(199,242,132,.13)"/>`+
    `<rect x="${(vx-vs/2).toFixed(1)}" y="${(vy-vs/2).toFixed(1)}" width="${vs}" height="${vs}" rx="7" fill="#111413" stroke="#c7f284" stroke-width="2.2"/>`+
    `<image href="${vlogo}" x="${(vx-vs/2+5).toFixed(1)}" y="${(vy-vs/2+5).toFixed(1)}" width="${vs-10}" height="${vs-10}" preserveAspectRatio="xMidYMid meet"/>`+
    `<line x1="${vx.toFixed(1)}" y1="${(vy-vs/2).toFixed(1)}" x2="${cxL}" y2="${(+cyL+14).toFixed(1)}" stroke="rgba(199,242,132,.55)" stroke-width="1"/>`+
    `<g transform="translate(${cxL},${cyL})"><text x="0" y="0" fill="#c7f284" font-size="10.5" font-weight="900" letter-spacing=".5">Variational implied</text>`+
    `<text x="0" y="16" fill="#eafff6" font-size="15" font-weight="900">${fmtBig(mcap)}</text></g>`;
  svg.innerHTML=`<defs>`+
    `<linearGradient id="valTrend" x1="0" y1="1" x2="1" y2="0"><stop offset="0" stop-color="#4f7fc4"/><stop offset="1" stop-color="#c7f284"/></linearGradient></defs>`+
    grid+trend+dots+legend+hero;
  const side=$('#valSide');
  if(side){
    const keyPeers=['Hyperliquid','Lighter','Aster','Jupiter','edgeX','dYdX'];
    const rows=keyPeers.map(n=>VAL_COMPS.find(c=>c.n===n)).filter(Boolean).map(c=>({n:c.n,mc:c.mc,imp:valPred(c.oi),prem:c.mc/valPred(c.oi)}));
    const chip=n=>PLOGO[n]?`<img class="vs-logo" src="${PLOGO[n]}" alt="" width="20" height="20" loading="lazy" decoding="async" style="width:20px!important;height:20px!important;min-width:20px!important;max-width:20px!important;min-height:20px!important;max-height:20px!important;object-fit:contain!important">`:`<span class="vs-dot"></span>`;
    const status=p=>p>=1.08?{cls:'premium',word:'PREMIUM'}:p<=0.92?{cls:'discount',word:'DISCOUNT'}:{cls:'fair',word:'NEAR MODEL'};
    side.innerHTML=`<div class="vs-h"><span>Key peers vs model</span><span class="vs-hs">${escapeHTML(VAL_MCAP_ASOF)}</span></div>`+
      `<div class="vs-row me"><span class="n">${chip('Variational')}<span class="vs-nm"><b>Variational</b><small>no traded MCAP yet</small></span></span><span class="vs-mcap"><b>${fmtBig(mcap)}</b><small>model est.</small></span><span class="v fair"><b>PRE-TGE</b><small>not priced</small></span></div>`+
      rows.map(r=>{const s=status(r.prem),pct=(r.prem-1)*100;return `<div class="vs-row"><span class="n">${chip(r.n)}<span class="vs-nm"><b>${escapeHTML(r.n)}</b><small>Model ${fmtBig(r.imp)}</small></span></span><span class="vs-mcap"><b>${fmtBig(r.mc)}</b><small>actual MCAP</small></span><span class="v ${s.cls}" title="Actual market cap divided by model-implied market cap"><b>${pct>=0?'+':''}${pct.toFixed(0)}%</b><small>${s.word} · ${r.prem.toFixed(2)}x</small></span></div>`}).join('');}
  const note=$('#valNote');
  if(note)note.innerHTML=`$VAR has no traded market cap before TGE. The ${fmtBig(mcap)} figure is a model estimate, not a current price. Model: MCAP ≈ ${VAL_FIT.A.toFixed(1)} × OI<sup>${VAL_FIT.B}</sup>, R² ${VAL_FIT.r2}. Market caps and available OI update from <a href="https://www.coingecko.com/" target="_blank" rel="noopener">CoinGecko</a>. Framework reference: <a href="https://www.perpetualpulse.xyz/" target="_blank" rel="noopener">Perpetual Pulse</a>. Not financial advice.`;
}

async function refreshValuationMcaps(){
  try{
    const ids=VAL_COMPS.map(c=>c.cg).filter(Boolean).join(',');
    const url='https://api.coingecko.com/api/v3/simple/price?ids='+encodeURIComponent(ids)+'&vs_currencies=usd&include_market_cap=true&include_last_updated_at=true';
    const res=await fetch(url);
    if(!res.ok)throw new Error('coingecko mcap http '+res.status);
    const data=await res.json();
    let hit=0,latest=0;
    VAL_COMPS.forEach(c=>{
      const live=data[c.cg];
      if(live&&Number.isFinite(+live.usd_market_cap)&&+live.usd_market_cap>0){
        c.mc=+live.usd_market_cap;
        c.mcLive=true;
        hit++;
        latest=Math.max(latest,+live.last_updated_at||0);
      }
    });
    if(!hit)throw new Error('no current market caps');
    const stamp=latest?new Date(latest*1000):new Date();
    VAL_MCAP_ASOF='Live CoinGecko · '+stamp.toLocaleString('en-US',{month:'short',day:'2-digit',hour:'2-digit',minute:'2-digit',timeZoneName:'short'});
    renderValuation();
  }catch(err){
    console.warn('Valuation market-cap sync fell back to snapshot:',err);
    renderValuation();
  }
}
/* ---------- live perp-DEX board via CoinGecko (free, CORS-open) ----------
   OI & 24h volume come back in BTC; multiply by live BTC price for USD.
   TVL / fees / leverage stay from the maintained snapshot (not on this feed).
   DEXs CoinGecko doesn't track (Jupiter/Drift/GMX) keep snapshot values, flagged. */
const CG_NAME={'Hyperliquid':'Hyperliquid','Aster':'Aster','Variational Omni':'Variational','Lighter':'Lighter',
  'GRVT':'GRVT','Ostium':'Ostium','edgeX':'edgeX','Extended':'Extended','ApeX Omni':'ApeX Protocol',
  'Pacifica':'Pacifica','Backpack':'Backpack','Vest Exchange':'Vest Exchange'};
function setBoardLive(state,label){
  const el=$('#boardLive'); if(!el)return;
  el.className='live-pill'+(state==='on'?' on':state==='err'?' err':'');
  el.replaceChildren(document.createElement('i'),document.createTextNode(String(label)));
}
async function refreshPerpBoard(){
  try{
    const [exRes,pxRes]=await Promise.all([
      fetch('https://api.coingecko.com/api/v3/derivatives/exchanges?per_page=100'),
      fetch('https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd')
    ]);
    if(!exRes.ok||!pxRes.ok)throw new Error('coingecko http '+exRes.status+'/'+pxRes.status);
    const ex=await exRes.json(), px=await pxRes.json();
    const btc=px&&px.bitcoin&&px.bitcoin.usd;
    if(!btc||!Array.isArray(ex))throw new Error('bad coingecko payload');
    const live={};
    ex.forEach(e=>{const nm=String(e.name||'').replace(/\s*\(futures\)\s*$/i,'').trim(); const key=CG_NAME[nm]; if(!key)return;
      live[key]={oi:(+e.open_interest_btc||0)*btc, vol:(+e.trade_volume_24h_btc||0)*btc, pairs:e.number_of_perpetual_pairs};
    });
    let hit=0;
    PEERS.list.forEach(p=>{const l=live[p.n];
      if(l&&l.oi>0){p.oi=l.oi; p.vol=l.vol; if(l.pairs!=null)p.pairs=l.pairs; p.live=true; hit++;}
      else p.live=false;
    });
    if(!hit)throw new Error('no exchange matches');
    PEERS.list.sort((a,b)=>b.oi-a.oi);
    const total=PEERS.list.reduce((s,p)=>s+(p.oi||0),0);
    const va=PEERS.list.find(p=>p.me), hl=PEERS.list.find(p=>p.n==='Hyperliquid');
    PEERS.total=total; PEERS.count=PEERS.list.length;
    PEERS.varRank=PEERS.list.findIndex(p=>p.me)+1;
    if(va&&total)PEERS.varShare=+(va.oi/total*100).toFixed(1);
    if(hl&&va&&va.oi)PEERS.vsHl=+(hl.oi/va.oi).toFixed(1);
    const li=live['Lighter']; if(li&&li.oi>0){VSL.li.oi=li.oi; VSL.li.vol1d=li.vol;}
    if(hl){VSL.hl.oi=hl.oi; VSL.hl.vol1d=hl.vol;}
    PEERS.live=true;
    const t=new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});
    PEERS.asOf='Live · CoinGecko · '+t;
    renderPeers(); renderPulseTable(); renderVsLighter(); renderKing(); renderValuation();
    setBoardLive('on','Live · '+t);
    refreshLlamaOi();
  }catch(err){
    console.warn('Perp board live sync fell back to snapshot:',err);
    if(!PEERS.live){PEERS.asOf='Snapshot · '+(PEERS.snapAsOf||'last saved'); renderPeers(); renderPulseTable(); renderVsLighter(); renderValuation();}
    renderKing();
    if(!PEERS.live)setBoardLive('err','Snapshot');
    refreshLlamaOi();
  }
}

/* Exact market activity. DeFiLlama exposes both protocol histories through its
   public v2 chart routes; the official Variational endpoint supplies the live
   rolling-24h volume and current OI used by the same DeFiLlama adapter. */
const MARKET_URLS={
  volume:'https://api.llama.fi/v2/chart/derivatives/protocol/variational',
  oi:'https://api.llama.fi/v2/chart/open-interest/protocol/variational?dataType=openInterestAtEnd',
  live:'https://omni-client-api.prod.ap-northeast-1.variational.io/metadata/stats'
};
const MARKET_ACTIVITY={volume:[],oi:[],live:null,days:90,historyAt:null,liveAt:null,errors:{history:'',live:''}};
let MARKET_HISTORY_SYNCING=false,MARKET_LIVE_SYNCING=false;
const marketDay=ts=>new Date(Number(ts)*1000).toISOString().slice(0,10);
const marketBig=n=>n>=1e9?'$'+(n/1e9).toFixed(2)+'B':n>=1e6?'$'+(n/1e6).toFixed(2)+'M':n>=1e3?'$'+(n/1e3).toFixed(1)+'K':fmtUSD(n);
const marketExact=(n,dp=0)=>Number.isFinite(+n)?fmtUSD(+n,dp):'—';
async function fetchMarketJson(url,timeout=12000){
  const ctrl=new AbortController(),timer=setTimeout(()=>ctrl.abort(),timeout);
  try{
    const r=await fetch(url,{signal:ctrl.signal,cache:'no-store'});
    if(!r.ok)throw new Error('HTTP '+r.status);
    return await r.json();
  }finally{clearTimeout(timer)}
}
function recalcVariationalPeer(){
  const vp=PEERS.list.find(p=>p.me);
  if(vp){vp.oi=MKT.oi;vp.vol=MKT.vol.d1;vp.live=true;}
  OI_SRC='llama';
  PEERS.list.sort((a,b)=>b.oi-a.oi);
  PEERS.total=PEERS.list.reduce((s,p)=>s+(p.oi||0),0);
  PEERS.varRank=PEERS.list.findIndex(p=>p.me)+1;
  const va=PEERS.list.find(p=>p.me),hl=PEERS.list.find(p=>p.n==='Hyperliquid');
  if(va&&PEERS.total)PEERS.varShare=+(va.oi/PEERS.total*100).toFixed(1);
  if(hl&&va&&va.oi)PEERS.vsHl=+(hl.oi/va.oi).toFixed(1);
}
function applyMarketModels(){
  const vols=MARKET_ACTIVITY.volume,ois=MARKET_ACTIVITY.oi,live=MARKET_ACTIVITY.live;
  const sumLast=n=>vols.slice(-n).reduce((s,x)=>s+x.v,0);
  if(vols.length){
    MKT.vol.d7=sumLast(7);
    MKT.vol.d30=sumLast(30);
    MKT.vol.cum=live?.cumulativeVolume||vols.reduce((s,x)=>s+x.v,0);
  }
  if(live?.volume24h>0)MKT.vol.d1=live.volume24h;
  if(live?.oi>0)MKT.oi=live.oi;
  else if(ois.length)MKT.oi=ois[ois.length-1].v;
  MKT.asOf=MARKET_ACTIVITY.liveAt
    ?MARKET_ACTIVITY.liveAt.toLocaleString('en-US',{timeZone:'UTC',month:'short',day:'2-digit',hour:'2-digit',minute:'2-digit',hour12:false})+' UTC'
    :(ois[ois.length-1]?.d||MKT.asOf);
  MKT.src='DeFiLlama v2 daily series + Variational official live stats';
  if(ois.length){
    OI_HIST.splice(0,OI_HIST.length,...ois.map(x=>[x.d,x.v]));
    _OIMAP.clear();OI_HIST.forEach(([d,v])=>_OIMAP.set(d,v));
  }
  recalcVariationalPeer();
}
function renderMarketConsumers(){
  renderMarketActivity();
  renderPeers();renderPulseTable();renderVsLighter();renderKing();renderValuation();
  renderEfficiency();renderFeeOi();
}
function renderMarketActivity(){
  const svg=$('#marketActivityChart');if(!svg)return;
  const vols=MARKET_ACTIVITY.volume,ois=MARKET_ACTIVITY.oi,live=MARKET_ACTIVITY.live;
  const put=(main,exact,value,dp=0)=>{
    const valid=value!==null&&value!==undefined&&Number.isFinite(Number(value));
    const a=$(main),b=$(exact);if(a)a.textContent=valid?marketBig(Number(value)):'—';
    if(b){
      b.textContent=valid?marketExact(Number(value),dp):'waiting for source';
      b.title=valid?b.textContent:'';
    }
  };
  put('#marketLiveVol','#marketLiveVolExact',live?.volume24h,2);
  put('#marketLiveOi','#marketLiveOiExact',live?.oi,2);
  put('#marketVol7d','#marketVol7dExact',vols.length?vols.slice(-7).reduce((s,x)=>s+x.v,0):null);
  put('#marketVol30d','#marketVol30dExact',vols.length?vols.slice(-30).reduce((s,x)=>s+x.v,0):null);
  renderDailyBrief();
  const sync=$('#marketSync');
  if(sync){
    const errors=Object.values(MARKET_ACTIVITY.errors).filter(Boolean);
    const dailyThrough=vols.at(-1)?.d;
    sync.classList.toggle('error',errors.length>0);
    sync.textContent=errors.length
      ?errors.join(' · ')+' · showing last exact observation'
      :MARKET_ACTIVITY.liveAt
        ?'Live synced '+MARKET_ACTIVITY.liveAt.toLocaleTimeString('en-US',{timeZone:'UTC',hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false})+' UTC'+(dailyThrough?' · daily through '+dailyThrough:'')
        :'Syncing exact data…';
  }
  if(!vols.length||!ois.length){
    svg.innerHTML='<text x="50%" y="50%" fill="#7d8aa5" text-anchor="middle" font-family="monospace" font-size="12">Loading exact DeFiLlama daily series…</text>';
    return;
  }
  const vm=new Map(vols.map(x=>[x.d,x.v])),om=new Map(ois.map(x=>[x.d,x.v]));
  let rows=[...new Set([...vm.keys(),...om.keys()])].sort().map(d=>({d,vol:vm.get(d),oi:om.get(d)})).filter(x=>Number.isFinite(x.vol)&&Number.isFinite(x.oi));
  if(MARKET_ACTIVITY.days)rows=rows.slice(-MARKET_ACTIVITY.days);
  if(rows.length<2)return;
  const {W,H}=chartDims(svg,960,330),pl=74,pr=78,pt=26,pb=42,n=rows.length;
  const X=i=>pl+i/Math.max(1,n-1)*(W-pl-pr);
  const vMax=Math.max(...rows.map(x=>x.vol))*1.12,oMax=Math.max(...rows.map(x=>x.oi))*1.12;
  const YV=v=>pt+(1-v/Math.max(1,vMax))*(H-pt-pb);
  const YO=v=>pt+(1-v/Math.max(1,oMax))*(H-pt-pb);
  let grid='';
  for(let i=0;i<=4;i++){
    const y=pt+(H-pt-pb)*i/4,v=vMax*(1-i/4),o=oMax*(1-i/4);
    grid+=`<line x1="${pl}" y1="${y}" x2="${W-pr}" y2="${y}" stroke="#243244" stroke-opacity=".55"/>`+
      `<text class="axis" x="${pl-9}" y="${y+4}" text-anchor="end">${marketBig(v).replace('$','')}</text>`+
      `<text class="axis" x="${W-pr+9}" y="${y+4}">${marketBig(o).replace('$','')}</text>`;
  }
  const volumeLine=rows.map((x,i)=>`${i?'L':'M'}${X(i).toFixed(1)} ${YV(x.vol).toFixed(1)}`).join(' ');
  const oiLine=rows.map((x,i)=>`${i?'L':'M'}${X(i).toFixed(1)} ${YO(x.oi).toFixed(1)}`).join(' ');
  const ticks=Math.min(W<520?5:7,n);
  const tickIndices=[...new Set(Array.from({length:ticks},(_,i)=>Math.round(i*(n-1)/Math.max(1,ticks-1))))];
  const dates=tickIndices.map(i=>`<text class="axis-date" x="${X(i)}" y="${H-14}" text-anchor="${i===0?'start':i===n-1?'end':'middle'}">${mdShort(rows[i].d)}</text>`).join('');
  const last=rows[n-1],lx=X(n-1);
  svg.innerHTML=`
    <text class="axis" x="${pl}" y="${pt-10}" fill="#55a8ff">DAILY PERP VOLUME</text>
    <text class="axis" x="${W-pr}" y="${pt-10}" fill="#ff7ba0" text-anchor="end">OPEN INTEREST · DAILY CLOSE</text>
    ${grid}
    <path d="${volumeLine}" fill="none" stroke="#4c9eff" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"/>
    <path d="${oiLine}" fill="none" stroke="#ff4d83" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"/>
    <circle cx="${lx}" cy="${YV(last.vol)}" r="3.6" fill="#4c9eff"/>
    <circle cx="${lx}" cy="${YO(last.oi)}" r="3.6" fill="#ff4d83"/>
    ${dates}<rect x="${pl}" y="${pt}" width="${W-pl-pr}" height="${H-pt-pb}" fill="transparent"/>`;
  const tt=$('#tt');
  svg.onmousemove=e=>{
    const rc=svg.getBoundingClientRect();
    let i=Math.round((((e.clientX-rc.left)/rc.width*W)-pl)/(W-pl-pr)*(n-1));i=clamp(i,0,n-1);
    const d=rows[i];
    tt.innerHTML=`<b>${d.d} · UTC daily observation</b><br>Perp Volume <b>${marketExact(d.vol)}</b><br>Open Interest <b>${marketExact(d.oi)}</b>`;
    placeTT(e);
  };
  svg.onmouseleave=()=>{tt.style.opacity=0;};
}
async function refreshMarketHistory(){
  if(MARKET_HISTORY_SYNCING)return;MARKET_HISTORY_SYNCING=true;
  try{
    const [volRaw,oiRaw]=await Promise.all([fetchMarketJson(MARKET_URLS.volume),fetchMarketJson(MARKET_URLS.oi)]);
    const normalize=a=>(Array.isArray(a)?a:[]).map(x=>({d:marketDay(x[0]),v:Number(x[1])})).filter(x=>/^\d{4}-\d{2}-\d{2}$/.test(x.d)&&Number.isFinite(x.v)&&x.v>=0).sort((a,b)=>a.d.localeCompare(b.d));
    const volume=normalize(volRaw),oi=normalize(oiRaw);
    if(volume.length<2||oi.length<2)throw new Error('daily series incomplete');
    MARKET_ACTIVITY.volume=volume;MARKET_ACTIVITY.oi=oi;MARKET_ACTIVITY.historyAt=new Date();MARKET_ACTIVITY.errors.history='';
    applyMarketModels();renderMarketConsumers();
  }catch(err){MARKET_ACTIVITY.errors.history='Daily history delayed';console.warn('Exact DeFiLlama market history sync failed:',err);renderMarketActivity()}
  finally{MARKET_HISTORY_SYNCING=false}
}
async function refreshMarketLive(){
  if(MARKET_LIVE_SYNCING)return;MARKET_LIVE_SYNCING=true;
  try{
    const s=await fetchMarketJson(MARKET_URLS.live,15000);
    const volume24h=Number(s?.total_volume_24h),oi=Number(s?.open_interest),cumulativeVolume=Number(s?.cumulative_volume);
    if(!(volume24h>0&&oi>0))throw new Error('live fields missing');
    MARKET_ACTIVITY.live={volume24h,oi,cumulativeVolume};MARKET_ACTIVITY.liveAt=new Date();MARKET_ACTIVITY.errors.live='';
    applyMarketModels();renderMarketConsumers();
  }catch(err){MARKET_ACTIVITY.errors.live='Live stats delayed';console.warn('Variational live market sync failed:',err);renderMarketActivity()}
  finally{MARKET_LIVE_SYNCING=false}
}
