function renderFeeOi(){
  const svg=$('#foiChart'); if(!svg)return;
  const startD=addDays(SERIES[0].d,30);            // begin once the trailing-30D window is full
  const data=feeOiHistory().filter(x=>x.d>=startD);
  if(data.length<2){svg.innerHTML='';return;}
  const first=data[0], last=data[data.length-1], n=data.length;
  const oiG=(last.oi/first.oi-1)*100, feeG=(last.rev/first.rev-1)*100;
  const rd=$('#foiRead');
  if(rd)rd.innerHTML=
    `<div class="fr-item"><div class="fr-v oi">${(oiG>=0?'+':'')+oiG.toFixed(0)}%</div><div class="fr-l">Open interest · since ${mdShort(first.d)}</div></div>`+
    `<div class="fr-item"><div class="fr-v fee">${(feeG>=0?'+':'')+feeG.toFixed(0)}%</div><div class="fr-l">Treasury fees (30D) · same window</div></div>`+
    `<div class="fr-item"><div class="fr-v y">${first.yield.toFixed(1)}% → ${last.yield.toFixed(1)}%</div><div class="fr-l">Fee yield on OI · per year</div></div>`+
    `<div class="fr-item"><div class="fr-v ${feeG>=oiG?'fee':'oi'}">${feeG>=oiG?'Fees outran OI':'OI outran fees'}</div><div class="fr-l">${feeG>=oiG?'monetizing OI better over time':'capacity grew faster than fees'}</div></div>`;
  const {W,H}=chartDims(svg,720,320),pl=52,pr=54,pt=26,gap=32,pb=34;
  const panelH=(H-pt-pb-gap)/2, aTop=pt,aBot=aTop+panelH,bTop=aBot+gap,bBot=bTop+panelH;
  const X=i=>pl+i/(n-1)*(W-pl-pr);
  const idxOi=data.map(d=>d.oi/first.oi*100), idxFee=data.map(d=>d.rev/first.rev*100);
  const hi=Math.max(...idxOi,...idxFee)*1.06, lo=Math.min(100,...idxOi,...idxFee)*0.95;
  const YA=v=>aTop+(1-(v-lo)/Math.max(1,hi-lo))*panelH;
  const ys=data.map(d=>d.yield), ymax=Math.max(...ys)*1.15;
  const YB=v=>bTop+(1-v/ymax)*panelH;
  const path=(arr,yfn)=>arr.map((v,i)=>`${i?'L':'M'}${X(i).toFixed(1)} ${yfn(v).toFixed(1)}`).join(' ');
  let gA='';[100,hi].concat([lo]).forEach(()=>{});
  for(const v of [lo,100,hi]){const y=YA(v);gA+=`<line x1="${pl}" y1="${y}" x2="${W-pr}" y2="${y}" stroke="${v===100?'#2a3750':'#16203038'}" ${v===100?'stroke-dasharray="3 3"':''}/>`+`<text class="axis" x="${pl-8}" y="${y+4}" text-anchor="end">${Math.round(v)}</text>`;}
  let gB='';for(let g=0;g<=2;g++){const v=ymax*g/2,y=YB(v);gB+=`<line x1="${pl}" y1="${y}" x2="${W-pr}" y2="${y}" stroke="#16203038"/>`+`<text class="axis" x="${pl-8}" y="${y+4}" text-anchor="end">${v.toFixed(1)}%</text>`;}
  const yArea=path(ys,YB)+`L${X(n-1)} ${YB(0)} L${X(0)} ${YB(0)} Z`;
  let dates='';data.forEach((d,i)=>{if(d.d.slice(-2)==='01'||i===n-1)dates+=`<text class="axis-date" x="${X(i)}" y="${H-12}" text-anchor="${i===n-1?'end':'middle'}">${i===n-1?mdShort(d.d):d.d.slice(0,7)}</text>`;});
  svg.innerHTML=`
    <defs><linearGradient id="foiY" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#ffb547" stop-opacity=".26"/><stop offset="1" stop-color="#ffb547" stop-opacity="0"/></linearGradient>
    <filter id="foiG"><feGaussianBlur stdDeviation="2" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs>
    <text class="axis" x="${pl}" y="${aTop-9}" fill="#8a96b5">Indexed to 100 at ${mdShort(first.d)} — higher line grew faster</text>
    ${gA}
    <path d="${path(idxOi,YA)}" fill="none" stroke="#38e1ff" stroke-width="2.2" stroke-linejoin="round"/>
    <path d="${path(idxFee,YA)}" fill="none" stroke="#22e6a0" stroke-width="2.4" filter="url(#foiG)" stroke-linejoin="round"/>
    <circle cx="${X(n-1)}" cy="${YA(idxOi[n-1])}" r="3.5" fill="#38e1ff"/><text class="chart-label" x="${X(n-1)-6}" y="${clamp(YA(idxOi[n-1])+4,aTop+10,aBot-2)}" fill="#9fe9ff" text-anchor="end">OI ${Math.round(idxOi[n-1])}</text>
    <circle cx="${X(n-1)}" cy="${YA(idxFee[n-1])}" r="3.5" fill="#22e6a0"/><text class="chart-label" x="${X(n-1)-6}" y="${clamp(YA(idxFee[n-1])-8,aTop+10,aBot-2)}" fill="#65ffd2" text-anchor="end">Fees ${Math.round(idxFee[n-1])}</text>
    <text class="axis" x="${pl}" y="${bTop-9}" fill="#ffb547">Fee yield on OI (annualised treasury fees ÷ OI)</text>
    ${gB}
    <path d="${yArea}" fill="url(#foiY)"/>
    <path d="${path(ys,YB)}" fill="none" stroke="#ffb547" stroke-width="2.2" stroke-linejoin="round"/>
    <circle cx="${X(n-1)}" cy="${YB(ys[n-1])}" r="3.5" fill="#ffb547"/><text class="chart-label" x="${X(n-1)-6}" y="${clamp(YB(ys[n-1])-8,bTop+10,bBot-2)}" fill="#ffd39a" text-anchor="end">${ys[n-1].toFixed(1)}%/yr</text>
    ${dates}
    <rect id="foiHit" x="${pl}" y="${pt}" width="${W-pl-pr}" height="${H-pt-pb}" fill="transparent"/>`;
  const tt=$('#tt');
  svg.onmousemove=e=>{const rc=svg.getBoundingClientRect();let i=Math.round((( (e.clientX-rc.left)/rc.width*W)-pl)/(W-pl-pr)*(n-1));i=clamp(i,0,n-1);const d=data[i];
    tt.innerHTML=`${d.d}<br>OI <b>$${fmtK(d.oi)}</b> (idx ${Math.round(idxOi[i])})<br>Fees30 <b>${fmtUSD(d.rev)}</b> (idx ${Math.round(idxFee[i])})<br>Yield <b>${d.yield.toFixed(2)}%/yr</b>`;placeTT(e);};
  svg.onmouseleave=()=>{tt.style.opacity=0;};
}
function renderFeeRevenueHistory(){
  const svg=$('#frHist'); if(!svg)return;
  const data=feeRevenueHistory();
  if(data.length<2){svg.innerHTML='';return;}
  const first=data[0], last=data[data.length-1];
  const revChange=(last.rev/Math.max(1,first.rev)-1)*100;
  const needChange=(last.volPerRev/Math.max(1,first.volPerRev)-1)*100;
  if($('#frReadRev'))$('#frReadRev').textContent=fmtUSD(last.rev)+' / 30D';
  if($('#frReadNeed'))$('#frReadNeed').textContent='$'+fmtK(last.volPerRev)+' vol / $1';
  if($('#frReadSignal')){
    const signal=revChange>0&&needChange<0?'Health improving':revChange>0?'Revenue growing':'Watch closely';
    $('#frReadSignal').textContent=signal;
  }
  const {W,H}=chartDims(svg,720,260),pl=70,pr=34,pt=24,pb=38;
  const maxRev=Math.max(...data.map(d=>d.rev))*1.12;
  const maxNeed=Math.max(...data.map(d=>d.volPerRev))*1.08;
  const minNeed=Math.min(...data.map(d=>d.volPerRev))*.94;
  const X=i=>pl+i/(data.length-1)*(W-pl-pr);
  const YRev=v=>pt+(1-v/maxRev)*(H-pt-pb);
  const YNeed=v=>pt+(1-(v-minNeed)/Math.max(1,maxNeed-minNeed))*(H-pt-pb);
  let grid='';for(let g=0;g<=3;g++){
    const rv=maxRev*g/3,y=YRev(rv);
    grid+=`<line x1="${pl}" y1="${y}" x2="${W-pr}" y2="${y}" stroke="#16203040"/>`+
      `<text class="axis" x="${pl-10}" y="${y+4}" text-anchor="end">${fmtUSD(rv)}</text>`;
  }
  const revLine=data.map((d,i)=>`${i?'L':'M'}${X(i).toFixed(1)} ${YRev(d.rev).toFixed(1)}`).join(' ');
  const needLine=data.map((d,i)=>`${i?'L':'M'}${X(i).toFixed(1)} ${YNeed(d.volPerRev).toFixed(1)}`).join(' ');
  const area=revLine+`L${X(data.length-1).toFixed(1)} ${YRev(0)} L${X(0).toFixed(1)} ${YRev(0)} Z`;
  let dates='';data.forEach((d,i)=>{if(d.d.slice(-2)==='01'||i===data.length-1)dates+=`<text class="axis-date" x="${X(i)}" y="${H-10}" text-anchor="${i===data.length-1?'end':'middle'}">${i===data.length-1?mdShort(d.d):d.d.slice(0,7)}</text>`;});
  const lx=X(data.length-1);
  svg.innerHTML=`
    <defs>
      <linearGradient id="frRevArea" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#22e6a0" stop-opacity=".28"/><stop offset="1" stop-color="#22e6a0" stop-opacity="0"/></linearGradient>
      <filter id="frGlow"><feGaussianBlur stdDeviation="2.2" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
    </defs>
    ${grid}${dates}
    <path d="${area}" fill="url(#frRevArea)"/>
    <path d="${revLine}" fill="none" stroke="#22e6a0" stroke-width="2.4" filter="url(#frGlow)" stroke-linejoin="round"/>
    <path d="${needLine}" fill="none" stroke="#8b6cff" stroke-width="2.1" stroke-dasharray="5 4" stroke-linejoin="round"/>
    <circle cx="${lx}" cy="${YRev(last.rev)}" r="4" fill="#22e6a0" filter="url(#frGlow)"/>
    <circle cx="${lx}" cy="${YNeed(last.volPerRev)}" r="4" fill="#8b6cff"/>
    <text class="chart-label" x="${lx-7}" y="${clamp(YRev(last.rev)-10,pt+12,H-pb-10)}" fill="#65ffd2" text-anchor="end">${fmtUSD(last.rev)} earned in 30D</text>
    <text class="chart-label" x="${lx-7}" y="${clamp(YNeed(last.volPerRev)+18,pt+18,H-pb-6)}" fill="#d7ccff" text-anchor="end">$${fmtK(last.volPerRev)} volume for $1</text>
    <text class="axis" x="${pl}" y="${pt-8}" fill="#22e6a0">green up = more treasury revenue</text>
    <text class="axis" x="${pl+250}" y="${pt-8}" fill="#8b6cff">purple down = better monetization</text>`;
}
