function renderPointsDeadline(){
  if(!$('#ptsRemainPct'))return;
  const start=resetLocalTs(SERIES[0].d,0,0,0)*1000;
  const end=resetLocalTs('2026-09-30',23,59,59)*1000;
  const now=Date.now();
  const total=Math.max(1,end-start);
  const left=Math.max(0,end-now);
  const done=Math.min(1,Math.max(0,(now-start)/total));
  const remain=left/total;
  const days=Math.floor(left/864e5);
  const hours=Math.floor((left%864e5)/36e5);
  $('#ptsRemainPct').textContent=(remain*100).toFixed(2)+'% left';
  $('#ptsDonePct').textContent=(done*100).toFixed(2)+'%';
  $('#ptsDaysLeft').textContent=left>0?`${days}D ${hours}H left`:'deadline passed';
  $('#ptsDeadlineText').textContent='Ends Sep 30, 2026 · 11:59PM ET';
  $('#ptsProgress').style.setProperty('--p',(done*100).toFixed(2)+'%');
}
function renderDailyBrief(){
  const root=$('#dailyBrief');if(!root||SERIES.length<3)return;
  const earnings=dailyEarn();
  const latest=earnings[earnings.length-1],previous=earnings[earnings.length-2];
  const baselineRows=earnings.slice(Math.max(0,earnings.length-8),-1);
  const baseline=baselineRows.reduce((sum,row)=>sum+row.e,0)/Math.max(1,baselineRows.length);
  const vsPrevious=pctChange(latest.e,previous.e);
  const vsAverage=pctChange(latest.e,baseline);
  const cur=currentTreasuryBalance(),asOf=currentTreasuryDate();
  const base7=cumAt(addDays(asOf,-7)),base30=cumAt(addDays(asOf,-30));
  const earned7=Math.max(0,cur-base7),earned30=Math.max(0,cur-base30);
  const treasuryGrowth=pctChange(cur,base30);
  const live=MARKET_ACTIVITY.live;
  const volume=live?.volume24h||MKT.vol.d1;
  const oi=live?.oi||MKT.oi;
  const volumeObservation=MARKET_ACTIVITY.volume[MARKET_ACTIVITY.volume.length-1];
  const oiObservation=MARKET_ACTIVITY.oi[MARKET_ACTIVITY.oi.length-1];
  const volumeDelta=live&&volumeObservation?pctChange(volume,volumeObservation.v):null;
  const oiDelta=live&&oiObservation?pctChange(oi,oiObservation.v):null;
  const signedPct=value=>value==null||!Number.isFinite(value)?'—':`${value>=0?'+':'-'}${Math.abs(value).toFixed(1)}%`;
  const signedMoney=value=>`${value>=0?'+':'-'}${fmtUSD(Math.abs(value))}`;
  const signal=(value,up,down)=>value==null?0:value>=up?1:value<=down?-1:0;
  const score=signal(vsAverage,15,-20)*2+signal(volumeDelta,10,-10)+signal(oiDelta,5,-5);
  const status=score>=2?'momentum':score<=-2?'watch':'steady';
  const labels={momentum:'MOMENTUM',steady:'STEADY',watch:'WATCH'};
  const headlines={
    momentum:'Revenue is running above its recent baseline.',
    steady:'Variational is holding near its recent revenue pace.',
    watch:'Revenue and market activity need a closer look.'
  };
  const dateLabel=new Date(`${latest.d}T12:00:00Z`).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric',timeZone:'UTC'});
  const liveLabel=MARKET_ACTIVITY.liveAt
    ?MARKET_ACTIVITY.liveAt.toLocaleTimeString('en-US',{timeZone:'UTC',hour:'2-digit',minute:'2-digit',hour12:false})+' UTC'
    :'market snapshot';
  const setDelta=(selector,value,label)=>{
    const el=$(selector);if(!el)return;
    el.className='daily-brief-delta';
    if(value!=null&&Math.abs(value)>.05)el.classList.add(value>0?'up':'down');
    el.textContent=value==null?`Waiting for ${label}`:`${signedPct(value)} ${label}`;
  };

  root.dataset.status=status;
  $('#dailyBriefStatus').textContent=labels[status];
  $('#dailyBriefHeadline').textContent=headlines[status];
  $('#dailyBriefAsOf').textContent=`ET revenue through ${dateLabel} · ${liveLabel}`;
  $('#dailyBriefSummary').textContent=`The latest completed ET day produced ${fmtUSD(latest.e)} of treasury revenue (${signedPct(vsAverage)} versus its prior ${baselineRows.length}D average). Live open interest is ${marketBig(oi)} and rolling 24H volume is ${marketBig(volume)}; the treasury added ${fmtUSD(earned7)} over the trailing 7 days.`;

  $('#dailyBriefRevenue').textContent=signedMoney(latest.e);
  const revenueDelta=$('#dailyBriefRevenueDelta');
  revenueDelta.className='daily-brief-delta';
  if(vsAverage!=null&&Math.abs(vsAverage)>.05)revenueDelta.classList.add(vsAverage>0?'up':'down');
  revenueDelta.textContent=`${signedPct(vsPrevious)} DoD · ${signedPct(vsAverage)} vs prior ${baselineRows.length}D avg`;
  $('#dailyBriefBurn').textContent=`At least ${fmtUSD(Math.max(0,latest.e*MKT.burnShare))} buyback-burn floor`;
  $('#dailyBriefVolume').textContent=marketBig(volume);
  setDelta('#dailyBriefVolumeDelta',volumeDelta,volumeObservation?`vs ${mdShort(volumeObservation.d)} daily observation`:'daily comparison');
  $('#dailyBriefOi').textContent=marketBig(oi);
  setDelta('#dailyBriefOiDelta',oiDelta,oiObservation?`vs ${mdShort(oiObservation.d)} daily close`:'daily close');
  $('#dailyBriefSevenDay').textContent='+'+fmtUSD(earned7);
  $('#dailyBriefSevenDayRate').textContent=`${fmtUSD(earned7/7)}/day trailing pace`;
  $('#dailyBriefTreasury').textContent=fmtUSD(cur);
  const growth=$('#dailyBriefTreasuryGrowth');
  growth.className='daily-brief-delta'+(treasuryGrowth>0?' up':treasuryGrowth<0?' down':'');
  growth.textContent=`+${fmtUSD(earned30)} · ${signedPct(treasuryGrowth)} over 30D`;
  $('#dailyBriefSignal').innerHTML=`<b>Signal:</b> ${signedPct(vsAverage)} revenue vs prior ${baselineRows.length}D average · ${signedPct(volumeDelta)} live volume · ${signedPct(oiDelta)} live OI versus latest daily observations.`;
  $('#dailySourceTreasuryAsOf').textContent=`Balance live · daily revenue through ${dateLabel} ET`;
  $('#dailySourceMarketAsOf').textContent=MARKET_ACTIVITY.liveAt?`Live API synced ${liveLabel}`:'Showing the latest saved market snapshot';
  $('#dailySourceHistoryAsOf').textContent=`Volume through ${volumeObservation?.d||'—'} UTC · OI through ${oiObservation?.d||'—'} UTC`;
  $('#dailySourceReportAsOf').textContent=`Latest report in dataset: ${BIWEEKLY.asOf}`;

  const post=[
    `Variational Daily VAR News — ${dateLabel} ET`,
    '',
    `Treasury ${signedMoney(latest.e)} (${signedPct(vsAverage)} vs 7D avg)`,
    `24H volume ${marketBig(volume)}`,
    `Open interest ${marketBig(oi)}`,
    `7D treasury +${marketBig(earned7)}`,
    `Treasury held ${marketBig(cur)}`,
    '',
    `Status: ${labels[status]}`
  ].join('\n');
  const newsUrl='https://variationalbuybackdashboard.vercel.app/#daily-news';
  const sourceLine='Sources + live dashboard:';
  root.dataset.tweet=post+'\n\n'+sourceLine;
  root.dataset.url=newsUrl;
  root.dataset.report=root.dataset.tweet+'\n'+newsUrl;
  $('#dailyNewsPost').textContent=root.dataset.report;
  const xCount=root.dataset.tweet.length+25;
  const count=$('#dailyNewsCount');
  count.textContent=`~${xCount} / 280`;
  count.classList.toggle('over',xCount>280);
}
function renderChanges(){
  renderDailyBrief();
  renderEfficiency();
  renderBiweekly();
  renderMath();
  renderPointsCalc();
}

/* ---------- rate helpers & forecast state ---------- */
function dailyRate(days){const n=SERIES.length;if(n-1<days)days=n-1;return (SERIES[n-1].v-SERIES[n-1-days].v)/days;}
function allTimeRate(){const n=SERIES.length;const dd=Math.max(1,(new Date(SERIES[n-1].d)-new Date(SERIES[0].d))/864e5);return SERIES[n-1].v/dd;}
const rateOf={ '7d':()=>dailyRate(7), '30d':()=>dailyRate(30), '60d':()=>dailyRate(60), 'all':()=>allTimeRate() };
const FC={ rate:0, target:'2026-09-30', burn:30 };
const CHART={curveZoom:'all'};
function daysTo(dstr){return Math.max(0,Math.round((new Date(dstr+'T00:00:00Z')-new Date(SERIES[SERIES.length-1].d+'T00:00:00Z'))/864e5));}
function clamp(n,min,max){return Math.max(min,Math.min(max,n));}
function chartDims(svg,baseW,baseH){
  const r=svg.getBoundingClientRect();
  const cssW=Math.max(1,r.width||baseW), cssH=Math.max(1,r.height||baseH);
  const W=Math.max(260,Math.round(cssW/cssH*baseH));
  svg.setAttribute('viewBox',`0 0 ${W} ${baseH}`);
  return {W,H:baseH};
}

/* ---------- cumulative area chart + forecast overlay ---------- */
function renderCurve(){
  const svg=$('#curve'),{W,H}=chartDims(svg,720,340),pl=72,pr=32,pt=42,pb=42;
  const last=SERIES[SERIES.length-1], d0=SERIES[0].d;
  const nDays=daysTo(FC.target);                 // forecast horizon
  $('#curveTag').textContent='actual + '+nDays+'d forecast';
  document.querySelectorAll('#curveZoom button').forEach(b=>b.classList.toggle('on',b.dataset.z===CHART.curveZoom));
  const rLo=Math.min(dailyRate(60),allTimeRate()), rHi=dailyRate(7); // cone bounds
  const projBase=last.v+FC.rate*nDays, projHi=last.v+rHi*nDays;
  const visibleStart=CHART.curveZoom==='all'?d0:addDays(last.d,-Number(CHART.curveZoom));
  const visible=SERIES.filter(p=>p.d>=visibleStart);
  const start=visible[0]||SERIES[0], startDay=start.d;
  const endDay=FC.target;
  const totalDays=Math.max(1,Math.round((new Date(endDay)-new Date(startDay))/864e5));
  const minActual=Math.min(...visible.map(p=>p.v));
  const ymin=CHART.curveZoom==='all'?0:Math.max(0,minActual-(last.v-minActual)*.22);
  const ymax=Math.max(projHi,projBase,last.v)*1.10;
  const yrange=Math.max(1,ymax-ymin);
  const dayOff=dstr=>Math.round((new Date(dstr)-new Date(startDay))/864e5);
  const X=off=>pl+(off/totalDays)*(W-pl-pr);
  const Y=v=>pt+(1-(v-ymin)/yrange)*(H-pt-pb);
  const V=y=>ymin+(1-(y-pt)/(H-pt-pb))*yrange;
  // historical line + area
  let d='';visible.forEach((p,i)=>{const o=dayOff(p.d);d+=(i?'L':'M')+X(o).toFixed(1)+' '+Y(p.v).toFixed(1)+' ';});
  const histEndX=X(dayOff(last.d));
  const baseY=Y(ymin);
  const area=d+`L${histEndX.toFixed(1)} ${baseY} L${X(0).toFixed(1)} ${baseY} Z`;
  // forecast paths (from last point to target)
  const oLast=dayOff(last.d), oTgt=totalDays;
  const fBase=`M${X(oLast).toFixed(1)} ${Y(last.v).toFixed(1)} L${X(oTgt).toFixed(1)} ${Y(projBase).toFixed(1)}`;
  const cone=`M${X(oLast).toFixed(1)} ${Y(last.v).toFixed(1)} L${X(oTgt).toFixed(1)} ${Y(projHi).toFixed(1)} `+
             `L${X(oTgt).toFixed(1)} ${Y(last.v+rLo*nDays).toFixed(1)} Z`;
  // gridlines
  let grid='';for(let g=0;g<=4;g++){const v=ymin+yrange*g/4,y=Y(v);
    grid+=`<line x1="${pl}" y1="${y}" x2="${W-pr}" y2="${y}" stroke="#16203040"/>`+
          `<text class="axis" x="${pl-10}" y="${y+4}" text-anchor="end">$${fmtK(v)}</text>`;}
  // month labels across full domain
  const monthEvery=CHART.curveZoom==='30'?1:CHART.curveZoom==='60'?1:CHART.curveZoom==='120'?2:1;
  let xl='';SERIES.forEach(p=>{
    if(p.d.slice(-2)!=='01'||p.d<startDay)return;
    const mo=+p.d.slice(5,7);
    if(CHART.curveZoom!=='all'||mo%monthEvery===0)
      xl+=`<text class="axis-date" x="${X(dayOff(p.d))}" y="${H-10}" text-anchor="middle">${p.d.slice(0,7)}</text>`;
  });
  if(CHART.curveZoom!=='all')xl+=`<text class="axis-date" x="${pl}" y="${H-10}" text-anchor="start">${startDay}</text>`;
  // today + target markers
  const mkToday=`<line x1="${histEndX}" y1="${pt}" x2="${histEndX}" y2="${H-pb}" stroke="#2a3750" stroke-dasharray="2 3"/>`;
  const tgtShort=new Date(resetMidnightTs(FC.target)*1000).toLocaleDateString('en-US',{month:'short',day:'numeric',timeZone:RESET_TZ.tz});
  const mkTgt=`<line x1="${X(oTgt)}" y1="${pt}" x2="${X(oTgt)}" y2="${H-pb}" stroke="rgba(139,108,255,.42)" stroke-dasharray="3 4"/>`+
    `<text class="axis-date" x="${X(oTgt)-4}" y="${H-10}" text-anchor="end">${tgtShort}</text>`;
  const pill=(x,y,text,fill,anchor='middle')=>{
    const w=Math.max(58,text.length*6.6+14), h=18;
    const bx=anchor==='end'?x-w:anchor==='start'?x:x-w/2;
    return `<g>
      <rect class="label-bg" x="${bx.toFixed(1)}" y="${(y-h+4).toFixed(1)}" width="${w.toFixed(1)}" height="${h}" rx="6"/>
      <text class="chart-label" x="${x.toFixed(1)}" y="${y.toFixed(1)}" fill="${fill}" text-anchor="${anchor}">${text}</text>
    </g>`;
  };
  const actualAnchor=histEndX>W-210?'end':'start';
  const lastLabelX=actualAnchor==='end'?histEndX-12:histEndX+12;
  const lastLabelY=clamp(Y(last.v)-10,pt+16,H-pb-14);
  const tgtAnchor=X(oTgt)>W-170?'end':'start';
  const tgtLabelX=tgtAnchor==='end'?X(oTgt)-12:X(oTgt)+12;
  const tgtLabelY=clamp(Y(projBase)-10,pt+16,H-pb-14);
  svg.innerHTML=`
   <defs>
     <linearGradient id="ag" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#22e6a0" stop-opacity=".38"/><stop offset="1" stop-color="#22e6a0" stop-opacity="0"/></linearGradient>
     <linearGradient id="lg" x1="0" y1="0" x2="1" y2="0"><stop offset="0" stop-color="#22e6a0"/><stop offset="1" stop-color="#38e1ff"/></linearGradient>
     <filter id="glow"><feGaussianBlur stdDeviation="3" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
   </defs>
   ${grid}${xl}${mkToday}${mkTgt}
   <path d="${area}" fill="url(#ag)"/>
   <path d="${cone}" fill="rgba(139,108,255,.10)" stroke="none"/>
   <path d="${d}" fill="none" stroke="url(#lg)" stroke-width="2.4" filter="url(#glow)" stroke-linejoin="round"/>
   <path d="${fBase}" fill="none" stroke="#8b6cff" stroke-width="2.2" stroke-dasharray="5 4" filter="url(#glow)"/>
   ${pill(lastLabelX,lastLabelY,fmtUSD(last.v),'#65ffd2',actualAnchor)}
   ${pill(tgtLabelX,tgtLabelY,fmtUSD(projBase),'#d7ccff',tgtAnchor)}
   <g class="drag-handle" data-handle="actual" style="color:#22e6a0" filter="url(#glow)">
     <circle class="handle-ring" cx="${histEndX}" cy="${Y(last.v)}" r="6.5"/>
     <circle cx="${histEndX}" cy="${Y(last.v)}" r="3.8" fill="#22e6a0"/>
     <circle cx="${histEndX}" cy="${Y(last.v)}" r="16" fill="transparent"/>
   </g>
   <g class="drag-handle" data-handle="forecast" style="color:#8b6cff" filter="url(#glow)">
     <circle class="handle-ring" cx="${X(oTgt)}" cy="${Y(projBase)}" r="7"/>
     <circle cx="${X(oTgt)}" cy="${Y(projBase)}" r="4.2" fill="#8b6cff"/>
     <circle cx="${X(oTgt)}" cy="${Y(projBase)}" r="16" fill="transparent"/>
   </g>`;
  // hover on history
  const tt=$('#tt');
  const setRateFromEvent=e=>{
    if(CHART.curveHandle==='actual'){
      const dy=CHART.curveStartY-e.clientY;
      FC.rate=Math.round(clamp(CHART.curveStartRate+dy*700,20000,90000)/1000)*1000;
    }else{
      const r=svg.getBoundingClientRect();
      const y=clamp((e.clientY-r.top)/r.height*H,pt,H-pb);
      const projected=Math.max(last.v,V(y));
      FC.rate=Math.round(clamp((projected-last.v)/Math.max(1,nDays),20000,90000)/1000)*1000;
    }
    $('#rate') && ($('#rate').value=FC.rate);
    [...document.querySelectorAll('.preset')].forEach(p=>p.classList.remove('on'));
    render();
  };
  svg.querySelectorAll('.drag-handle').forEach(h=>{
    h.addEventListener('pointerdown',e=>{
      CHART.curveDragging=true;
      CHART.curveHandle=h.dataset.handle;
      CHART.curveStartY=e.clientY;
      CHART.curveStartRate=FC.rate;
      svg.setPointerCapture?.(e.pointerId);
      setRateFromEvent(e);
      document.onpointermove=setRateFromEvent;
      document.onpointerup=()=>{CHART.curveDragging=false;CHART.curveHandle=null;document.onpointermove=null;document.onpointerup=null;};
    });
  });
  svg.onmousemove=e=>{
    if(CHART.curveDragging)return;
    const r=svg.getBoundingClientRect();const px=(e.clientX-r.left)/r.width*W;
    const off=(px-pl)/(W-pl-pr)*totalDays;
    const absDate=addDays(startDay,Math.round(off));
    if(absDate<=last.d){
      let i=SERIES.findIndex(p=>p.d>=absDate);i=i<0?SERIES.length-1:i;
      const p=SERIES[i], prev=SERIES[Math.max(0,i-1)];
      tt.innerHTML=`${p.d}<br><b>${fmtUSD(p.v)}</b>${i>0?`<br>+${fmtUSD(p.v-prev.v)} / day`:''}`;
    }
    else {
      const futureDays=Math.round((new Date(absDate)-new Date(last.d))/864e5);
      tt.innerHTML=`${absDate}<br><b>${fmtUSD(last.v+FC.rate*futureDays)}</b><br>forecast · $${fmtK(FC.rate)}/day`;
    }
    placeTT(e);
  };
  svg.onmouseleave=()=>tt.style.opacity=0;
}

/* ---------- forecast panel ---------- */
function renderForecast(){
  if(!$('#fcDays'))return;
  const last=SERIES[SERIES.length-1];
  const nDays=daysTo(FC.target);
  const projBase=last.v+FC.rate*nDays;
  const rLo=Math.min(dailyRate(60),allTimeRate()), rHi=dailyRate(7);
  const projLo=last.v+rLo*nDays, projHi=last.v+rHi*nDays;
  const tgtNice=new Date(resetMidnightTs(FC.target)*1000).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric',timeZone:RESET_TZ.tz});
  $('#fcDays').textContent=nDays+' days left';
  $('#tgtLbl').textContent=tgtNice;
  $('#rateEcho').textContent='$'+fmtK(FC.rate)+'/day';
  $('#tgtEcho').textContent=FC.target;
  $('#burnEcho').textContent=FC.burn+'%';
  $('#projVal').textContent=fmtUSD(projBase);
  $('#projAdd').textContent=`+${fmtUSD(projBase-last.v)} added in ${nDays} days`;
  $('#projRange').textContent=`range ${fmtUSD(projLo)} – ${fmtUSD(projHi)} (soft→hot pace)`;
  const bn=last.v*FC.burn/100, bp=projBase*FC.burn/100;
  $('#burnNow').textContent='≥ '+fmtUSD(bn);
  $('#burnProj').textContent='≥ '+fmtUSD(bp);
  $('#burnNote').innerHTML=`≥${FC.burn}% of protocol revenue is committed to purchase &amp; burn $VAR. Treasury revenue ≈ USDC captured here. Zero outflows so far → this is dry powder building up, not yet burned on-chain.`;
}

/* ---------- interval bar chart ---------- */
function renderBars(kind,rows){
  const svg=$('#bars'),{W,H}=chartDims(svg,380,230),pl=48,pr=16,pt=16,pb=36;
  const show=rows.slice(-18); // keep readable
  const rolling=show.map((r,i)=>{
    const w=show.slice(Math.max(0,i-3),i+1);
    return {...r,avg:w.reduce((s,x)=>s+x.added,0)/w.length};
  });
  const max=Math.max(...show.map(r=>r.added),...rolling.map(r=>r.avg))*1.08||1;
  const bw=(W-pl-pr)/show.length;
  const Y=v=>pt+(1-v/max)*(H-pt-pb);
  let grid='';for(let g=0;g<=3;g++){const v=max*g/3,y=Y(v);
    grid+=`<line x1="${pl}" y1="${y}" x2="${W-pr}" y2="${y}" stroke="#16203040"/>`+
          `<text x="${pl-6}" y="${y+3}" fill="#4a5674" font-size="9" text-anchor="end">$${fmtK(v)}</text>`;}
  const acc=getComputedStyle(document.documentElement).getPropertyValue(intMeta[kind].acc).trim();
  let bars='';show.forEach((r,i)=>{
    const x=pl+i*bw+bw*0.16,w=bw*0.68,y=Y(r.added),h=H-pb-y;
    const lblEvery=Math.ceil(show.length/6);
    bars+=`<rect x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${w.toFixed(1)}" height="${Math.max(1,h).toFixed(1)}" rx="2.5"
            fill="url(#bg)" data-i="${i}" class="barR"><title>${r.sD}→${r.eD}\n+${fmtUSD(r.added)} (${r.pct==null?'—':fmtPct(r.pct)})</title></rect>`;
    if(i%lblEvery===0||i===show.length-1)
      bars+=`<text x="${(x+w/2).toFixed(1)}" y="${H-20}" fill="#5a678a" font-size="8.5" text-anchor="middle" transform="rotate(0)">${mdShort(r.eD)}</text>`;
  });
  const avgLine=rolling.map((r,i)=>{
    const x=pl+i*bw+bw/2;
    return `${i?'L':'M'}${x.toFixed(1)} ${Y(r.avg).toFixed(1)}`;
  }).join(' ');
  const avgDots=rolling.map((r,i)=>{
    const x=pl+i*bw+bw/2, y=Y(r.avg);
    return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="2.2" fill="#ffb547" data-i="${i}" class="avgR"/>`;
  }).join('');
  const avgLast=rolling[rolling.length-1];
  svg.innerHTML=`<defs><linearGradient id="bg" x1="0" y1="0" x2="0" y2="1">
     <stop offset="0" stop-color="${acc}" stop-opacity=".95"/><stop offset="1" stop-color="${acc}" stop-opacity=".28"/></linearGradient></defs>
     ${grid}${bars}
     <path d="${avgLine}" fill="none" stroke="#ffb547" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"/>
     ${avgDots}
     <text x="${W-pr}" y="${Y(avgLast.avg)-7}" fill="#ffcf8a" font-size="9.5" text-anchor="end">$${fmtK(avgLast.avg)} avg</text>
     <text x="${pl}" y="${H-4}" fill="#4a5674" font-size="9">USDC added per ${intMeta[kind].lbl} (last ${show.length})</text>`;
  const tt=$('#tt');
  svg.querySelectorAll('.barR').forEach(b=>{
    b.onmousemove=e=>{const r=show[+b.dataset.i];
      tt.innerHTML=`${r.sD} → ${r.eD}<br><b>+${fmtUSD(r.added)}</b><br>${r.pct==null?'first period':fmtPct(r.pct)+' growth'} · ${fmtUSD(r.perDay)}/day`;
      placeTT(e);
    };
    b.onmouseleave=()=>tt.style.opacity=0;
  });
  svg.querySelectorAll('.avgR').forEach(d=>{
    d.onmousemove=e=>{const r=rolling[+d.dataset.i];
      tt.innerHTML=`${r.sD} → ${r.eD}<br><b>${fmtUSD(r.avg)}</b><br>4-period rolling average`;
      placeTT(e);
    };
    d.onmouseleave=()=>tt.style.opacity=0;
  });
}

/* ---------- earning velocity (rolling $/day) ---------- */
function rollRate(win){
  const out=[];
  for(let i=1;i<SERIES.length;i++){
    const w=Math.min(win,i);
    out.push({d:SERIES[i].d, r:(SERIES[i].v-SERIES[i-w].v)/w});
  }
  return out;
}
function renderVelocity(){
  const svg=$('#velo'),{W,H}=chartDims(svg,720,300),pl=72,pr=32,pt=28,pb=44;
  const R=rollRate(7), d0=R[0].d, last=R[R.length-1];
  const daily=SERIES.slice(1).map((p,i)=>({d:p.d, v:Math.max(0,p.v-SERIES[i].v)}));
  const span=Math.max(1,(new Date(last.d)-new Date(d0))/864e5);
  const avg=allTimeRate();
  const ymax=Math.max(...R.map(p=>p.r),...daily.map(p=>p.v),avg)*1.14;
  const dayOff=ds=>(new Date(ds)-new Date(d0))/864e5;
  const X=o=>pl+(o/span)*(W-pl-pr);
  const Y=v=>pt+(1-v/ymax)*(H-pt-pb);
  let line='';R.forEach((p,i)=>{line+=(i?'L':'M')+X(dayOff(p.d)).toFixed(1)+' '+Y(p.r).toFixed(1)+' ';});
  const x0=X(0),xN=X(dayOff(last.d));
  const area=line+`L${xN.toFixed(1)} ${Y(0)} L${x0.toFixed(1)} ${Y(0)} Z`;
  let grid='';for(let g=0;g<=3;g++){const v=ymax*g/3,y=Y(v);
    grid+=`<line x1="${pl}" y1="${y}" x2="${W-pr}" y2="${y}" stroke="#16203040"/>`+
          `<text class="axis" x="${pl-10}" y="${y+4}" text-anchor="end">$${fmtK(v)}</text>`;}
  const yA=Y(avg);
  const base=`<line x1="${pl}" y1="${yA}" x2="${W-pr}" y2="${yA}" stroke="#ffb547" stroke-dasharray="4 4" stroke-opacity=".55"/>`+
    `<text class="chart-label" x="${W-pr}" y="${yA-7}" fill="#ffb547" text-anchor="end" opacity=".9">all-time avg $${fmtK(avg)}/day</text>`;
  let xl='';SERIES.forEach(p=>{if(p.d.slice(-2)==='01'&&p.d>=d0){xl+=`<text class="axis-date" x="${X(dayOff(p.d))}" y="${H-10}" text-anchor="middle">${p.d.slice(0,7)}</text>`;}});
  const bw=Math.max(1.2,(W-pl-pr)/Math.max(1,daily.length)*.72);
  const bars=daily.map(p=>{
    const x=X(dayOff(p.d))-bw/2,y=Y(p.v),h=Y(0)-y;
    return `<rect class="veloBar" x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${bw.toFixed(1)}" height="${Math.max(1,h).toFixed(1)}" rx="1.5" fill="url(#vb)" data-d="${p.d}" data-v="${p.v.toFixed(2)}"/>`;
  }).join('');
  svg.innerHTML=`
   <defs>
     <linearGradient id="va" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#ffb547" stop-opacity=".32"/><stop offset="1" stop-color="#22e6a0" stop-opacity="0"/></linearGradient>
     <linearGradient id="vb" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#36ecff" stop-opacity=".45"/><stop offset="1" stop-color="#22e6a0" stop-opacity=".08"/></linearGradient>
     <linearGradient id="vl" x1="0" y1="0" x2="1" y2="0"><stop offset="0" stop-color="#38e1ff"/><stop offset=".55" stop-color="#22e6a0"/><stop offset="1" stop-color="#ffb547"/></linearGradient>
     <filter id="vglow"><feGaussianBlur stdDeviation="2.6" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
   </defs>
   ${grid}${xl}${bars}${base}
   <path d="${area}" fill="url(#va)"/>
   <path d="${line}" fill="none" stroke="url(#vl)" stroke-width="2.4" filter="url(#vglow)" stroke-linejoin="round"/>
   <circle cx="${xN}" cy="${Y(last.r)}" r="4" fill="#ffb547" filter="url(#vglow)"/>
   <text class="chart-label" x="${xN-6}" y="${clamp(Y(last.r)-10,pt+12,H-pb-8)}" fill="#ffd39a" text-anchor="end">$${fmtK(last.r)}/day</text>`;
  const mult=last.r/avg, ann=last.r*365;
  $('#veloStats').innerHTML=
    `<div class="vs"><span class="n hi">$${fmtK(last.r)}/day</span><span class="l">Now · 7-day avg</span></div>`+
    `<div class="vs"><span class="n">${mult.toFixed(1)}×</span><span class="l">vs all-time avg</span></div>`+
    `<div class="vs"><span class="n">$${fmtK(ann)}/yr</span><span class="l">Annualized run-rate</span></div>`;
  const tt=$('#tt');
  svg.onmousemove=e=>{const rc=svg.getBoundingClientRect();const px=(e.clientX-rc.left)/rc.width*W;
    let i=Math.round((px-pl)/(W-pl-pr)*span);i=Math.max(0,Math.min(R.length-1,i));const p=R[i];
    const day=daily.find(x=>x.d===p.d);
    tt.innerHTML=`${p.d}<br><b>$${fmtK(p.r)}/day</b><br>7-day avg pace${day?`<br>daily bar +${fmtUSD(day.v)}`:''}`;
    placeTT(e);
  };
  svg.onmouseleave=()=>tt.style.opacity=0;
}

/* ---------- table ---------- */
function renderTable(kind,rows){
  const max=Math.max(...rows.map(r=>r.added))||1;
  const body=rows.slice().reverse().map(r=>{
    const pct=r.pct==null?'<span class="muted">—</span>':`<span class="${r.pct>=0?'pos':'neg'}">${fmtPct(r.pct)}</span>`;
    const bw=(r.added/max*100).toFixed(1);
    return `<tr>
      <td>${r.sD} → ${r.eD}</td>
      <td class="muted">${fmtUSD(r.sV)}</td>
      <td>${fmtUSD(r.eV)}</td>
      <td class="barcell"><div class="bar" style="width:${bw}%"></div><span class="pos">+${fmtUSD(r.added)}</span></td>
      <td>${pct}</td>
      <td class="muted">${fmtUSD(r.perDay)}</td>
    </tr>`;
  }).join('');
  $('#tbl tbody').innerHTML=body;
}

