function ratePerSec(){return dailyRate(7)/86400;}
function renderTwaps(){
  const r=dailyRate(7);
  if($('#tw1h'))$('#tw1h').textContent='+'+fmtUSD(r/24);
  if($('#tw24h'))$('#tw24h').textContent='+'+fmtUSD(r);
  if($('#tw7d'))$('#tw7d').textContent='+'+fmtUSD(r*7);
}
function setDeltaPill(sel,cur,base){
  const el=$(sel), b=el?.querySelector('b');if(!el||!b)return;
  const pct=pctChange(cur,base);
  el.classList.remove('neg','flat');
  if(pct==null){b.textContent='—';el.classList.add('flat');return;}
  if(pct<0)el.classList.add('neg');
  else if(Math.abs(pct)<0.05)el.classList.add('flat');
  b.textContent=(pct>=0?'+':'')+pct.toFixed(2)+'%';
}
function renderHeaderDeltasFallback(){
  const n=SERIES.length, cur=currentTreasuryBalance();
  setDeltaPill('#hd7d',cur,SERIES[Math.max(0,n-8)].v);
}
/* actual on-chain added over trailing windows (12h / 24h / 7d) */
function renderActualsFallback(cur){
  const daily=Math.max(0,dailyRate(7));
  const values=[daily*.5,daily,daily*7];
  ['#ac12h','#ac24h','#ac7d'].forEach((sel,i)=>{const el=$(sel);if(el)el.textContent='~'+fmtUSD(values[i]);});
  setDeltaPill('#hd12',cur,Math.max(0,cur-values[0]));
  setDeltaPill('#hd24',cur,Math.max(0,cur-values[1]));
  setDeltaPill('#hd7d',cur,Math.max(0,cur-values[2]));
}
async function renderActuals(cur){
  try{
    const nowTs=Math.floor(Date.now()/1000);
    if(cur==null) cur=await balAt('latest');
    const [b12,b24,b7]=await Promise.all([
      balAt(blockAt(nowTs-12*3600)),
      balAt(blockAt(nowTs-24*3600)),
      balAt(blockAt(nowTs-7*86400))
    ]);
    $('#ac12h').textContent='+'+fmtUSD(Math.max(0,cur-b12));
    $('#ac24h').textContent='+'+fmtUSD(Math.max(0,cur-b24));
    $('#ac7d').textContent='+'+fmtUSD(Math.max(0,cur-b7));
    setDeltaPill('#hd12',cur,b12);
    setDeltaPill('#hd24',cur,b24);
    setDeltaPill('#hd7d',cur,b7);
  }catch(e){renderActualsFallback(cur??SERIES[SERIES.length-1].v);}
}
let _liveT0=performance.now();
let LIVE_BASE={balance:SERIES[SERIES.length-1].v,at:performance.now()};
let LIVE_HOUR_BASE={key:resetHourKey(),balance:SERIES[SERIES.length-1].v,at:performance.now()};
let _lastHourDom=0;
let _lastZoneDom=0;
function projectedBalance(){
  return LIVE_BASE.balance+ratePerSec()*((performance.now()-LIVE_BASE.at)/1000);
}
function todayBaseBalance(){
  return cumAt(addDays(resetDateKey(),-1));
}
function hourlyProfileWeights(date=resetDateKey()){
  const base=[.62,.54,.50,.48,.52,.62,.76,.94,1.12,1.30,1.42,1.36,1.22,1.18,1.28,1.46,1.60,1.52,1.34,1.18,1.02,.90,.78,.68];
  const dow=new Date(resetMidnightTs(date)*1000).toLocaleDateString('en-US',{weekday:'short',timeZone:RESET_TZ.tz});
  const weekend=dow==='Sat'||dow==='Sun';
  const shaped=base.map((w,h)=>{
    const euOverlap=h>=8&&h<=12?1.10:1;
    const usOpen=h>=9&&h<=16?1.16:1;
    const asia=h>=20||h<=1?1.08:1;
    return w*euOverlap*usOpen*asia*(weekend?.62:1);
  });
  const sum=shaped.reduce((a,b)=>a+b,0)||1;
  return shaped.map(x=>x/sum);
}
function projectedDayEarn(date=resetDateKey(),balance=projectedBalance()){
  const yesterday=addDays(date,-1);
  const actual=Math.max(0,balance-cumAt(yesterday));
  return Math.max(actual,dailyRate(7));
}
function renderProjectedHourlyEarnings(balance=projectedBalance()){
  const list=$('#tlogList'); if(!list)return;
  if(CALMODE!=='day'||(CAL.selectedDate&&CAL.selectedDate!==resetDateKey()))return;
  const {date,hour}=resetHourParts();
  const nowParts=tzParts(new Date());
  const mins=+nowParts.minute+(+nowParts.second/60);
  const weights=hourlyProfileWeights(date);
  const daily=projectedDayEarn(date,balance);
  const vals=[];
  for(let h=0;h<=hour;h++){
    let earned=daily*weights[h];
    if(h===hour)earned*=mins/60;
    vals.push({h,earned});
  }
  const max=Math.max(...vals.map(x=>x.earned),1);
  const rows=vals.map(x=>hourlyRow(x.h,x.earned,{current:x.h===hour,max,date,projected:true})).join('');
  list.innerHTML=rows || `<div class="tlog-row"><span class="tlog-t">—</span><span class="tlog-b">waiting for ET clock…</span><span class="tlog-d"></span></div>`;
  if($('#tlogMode'))$('#tlogMode').textContent='TODAY · ET / SGT';
  list.scrollTop=list.scrollHeight;
}
function updateCurrentHourRow(balance=projectedBalance()){
  const list=$('#tlogList'); if(!list)return;
  if(CALMODE!=='day'||(CAL.selectedDate&&CAL.selectedDate!==resetDateKey()))return;
  const {date,hour}=resetHourParts();
  const row=list.querySelector(`.tlog-row[data-hour="${hour}"]`);
  if(!row){renderProjectedHourlyEarnings(balance);return;}
  const projected=row.querySelector('.proj');
  const nowParts=tzParts(new Date());
  const mins=+nowParts.minute+(+nowParts.second/60);
  const earned=projected
    ? projectedDayEarn(date,balance)*hourlyProfileWeights(date)[hour]*(mins/60)
    : Math.max(0,balance-LIVE_HOUR_BASE.balance);
  const vals=[...list.querySelectorAll('.tlog-row')].map(r=>parseFloat((r.querySelector('.tlog-b')?.textContent||'').replace(/[^0-9.]/g,''))||0);
  const max=Math.max(...vals,earned,1);
  row.outerHTML=hourlyRow(hour,earned,{current:true,max,date,projected:!!projected});
}
async function renderHourlyEarnings(cur=projectedBalance()){
  const list=$('#tlogList'); if(!list)return;
  if(CALMODE!=='day'||(CAL.selectedDate&&CAL.selectedDate!==resetDateKey()))return;
  const {date,hour}=resetHourParts();
  const dayBase=todayBaseBalance();
  try{
    const marks=[dayBase];
    for(let h=1;h<=hour;h++){
      marks[h]=await balAt(blockAt(resetLocalTs(date,h)));
    }
    LIVE_HOUR_BASE={key:resetHourKey(),balance:marks[hour]??dayBase,at:performance.now()};
    const vals=[];
    for(let h=0;h<=hour;h++){
      const start=marks[h]??dayBase;
      const end=h===hour?cur:(marks[h+1]??start);
      const earned=Math.max(0,end-start);
      vals.push({h,earned});
    }
    const max=Math.max(...vals.map(x=>x.earned),1);
    const rows=vals.map(x=>hourlyRow(x.h,x.earned,{current:x.h===hour,max,date})).join('');
    list.innerHTML=rows;
    if($('#tlogMode'))$('#tlogMode').textContent='LIVE · ET / SGT';
    list.scrollTop=list.scrollHeight;
  }catch(_){
    LIVE_HOUR_BASE={key:resetHourKey(),balance:cur,at:performance.now()};
    renderProjectedHourlyEarnings(cur);
  }
}
function renderSelectedHourlyEarnings(dateStr,amount,complete){
  const list=$('#tlogList');if(!list)return;
  if(CALMODE!=='day'){
    list.innerHTML='<div class="tlog-empty">Hourly detail is available in Daily view. Weekly and monthly views show final totals only.</div>';
    if($('#tlogMode'))$('#tlogMode').textContent='FINAL TOTAL';
    return;
  }
  if(dateStr===resetDateKey()){
    renderProjectedHourlyEarnings(projectedBalance());
    return;
  }
  if(!complete||!amount){
    list.innerHTML='<div class="tlog-empty">This ET day has not closed yet. Its final total and hourly shape will appear after 00:00 ET.</div>';
    if($('#tlogMode'))$('#tlogMode').textContent='PENDING';
    return;
  }
  const weights=hourlyProfileWeights(dateStr);
  const vals=weights.map((weight,h)=>({h,earned:amount*weight}));
  const max=Math.max(...vals.map(x=>x.earned),1);
  list.innerHTML=vals.map(x=>hourlyRow(x.h,x.earned,{max,date:dateStr,estimated:true})).join('');
  if($('#tlogMode'))$('#tlogMode').textContent='ESTIMATED SHAPE · ET / SGT';
  list.scrollTop=0;
}
function tickLive(){
  const bal=projectedBalance();
  const hk=resetHourKey();
  if(hk!==LIVE_HOUR_BASE.key){
    LIVE_HOUR_BASE={key:hk,balance:bal,at:performance.now()};
    renderProjectedHourlyEarnings(bal);
  }
  const earned=Math.max(0,bal-LIVE_HOUR_BASE.balance);
  const whole=Math.floor(earned), cents=Math.floor((earned-whole)*100);
  const now=new Date(), hp=resetHourParts(now);
  const exactNow=resetTimeShort(now);
  const hourRange=hourRangeLabel(hp.date,hp.hour,RESET_TZ.tz,'ET');
  const asiaRange=hourRangeLabel(hp.date,hp.hour,ASIA_TZ.tz,ASIA_TZ.label);
  $('#ticker').innerHTML=fmtUSD(whole)+'<span class="cents">.'+String(cents).padStart(2,'0')+'</span>';
  $('#liveExactClock').textContent=exactNow+' ET';
  if($('#liveHourLabel'))$('#liveHourLabel').textContent=`Current ET hour · ${String(hp.hour).padStart(2,'0')}:00-${String((hp.hour+1)%24).padStart(2,'0')}:00`;
  $('#tickerSub').textContent=`${hourRange} / ${asiaRange} · earned so far`;
  $('#totalVal').textContent=fmtUSD(Math.floor(bal));
  renderImpliedSpreadTotal(bal);
  if(CALMODE==='day'&&CAL.selectedDate===hp.date){
    const todayEarned=Math.max(0,bal-cumAt(addDays(hp.date,-1)));
    $('#calAmt').textContent='+'+fmtUSD(todayEarned);
    if(CAL.sel)CAL.sel.amt='+'+fmtUSD(todayEarned);
  }
  if(performance.now()-_lastHourDom>1000){
    updateCurrentHourRow(bal);
    updateSelectedDayProgress();
    _lastHourDom=performance.now();
  }
  if(performance.now()-_lastZoneDom>30000){
    renderInspectorZoneClocks(now);
    _lastZoneDom=performance.now();
  }
}
function initRain(){
  const rain=$('#rain');if(!rain||RM)return;
  const coins=['$','$','¢','◇'];let h='';
  for(let i=0;i<14;i++)h+=`<i style="left:${(Math.random()*100).toFixed(1)}%;animation-duration:${(2+Math.random()*3).toFixed(1)}s;animation-delay:${(Math.random()*4).toFixed(1)}s;color:${i%2?'#22e6a0':'#38e1ff'}">${coins[i%coins.length]}</i>`;
  rain.innerHTML=h;
}
