let CALMODE='day', CAL={month:null};
function buildCalendar(){
  const de=dailyEarn();
  CAL.eMap=new Map(de.map(x=>[x.d,x.e]));
  CAL.wk=new Map();CAL.mo=new Map();
  de.forEach(x=>{const ws=weekStart(x.d),ym=x.d.slice(0,7);
    CAL.wk.set(ws,(CAL.wk.get(ws)||0)+x.e);CAL.mo.set(ym,(CAL.mo.get(ym)||0)+x.e);});
  CAL.maxDay=Math.max(...de.map(x=>x.e));
  CAL.maxWk=Math.max(...CAL.wk.values());CAL.maxMo=Math.max(...CAL.mo.values());
  CAL.first=SERIES[0].d;CAL.last=SERIES[SERIES.length-1].d;
  if(!CAL.month)CAL.month=CAL.last.slice(0,7);
  paintCalendar();
}
function cellVal(dateStr){
  if(CALMODE==='day')return {v:CAL.eMap.get(dateStr)||0,max:CAL.maxDay};
  if(CALMODE==='week')return {v:CAL.wk.get(weekStart(dateStr))||0,max:CAL.maxWk};
  return {v:CAL.mo.get(dateStr.slice(0,7))||0,max:CAL.maxMo};
}
const isClosedDailyTotal=dateStr=>dateStr<resetDateKey()&&dateStr<=CAL.last&&CAL.eMap.has(dateStr);
function calImpliedActivity(earn){
  const e=computeEff();
  return {
    spreadFees: earn/MKT.spreadShare,
    volume: earn*e.volPerRev,
    oi: earn*e.oiPerDayRev,
    burn: earn*MKT.burnShare
  };
}
const calMiniMoney=n=>n>=1e9?'$'+(n/1e9).toFixed(1)+'B':n>=1e6?'$'+(n/1e6).toFixed(1)+'M':n>=1e3?'$'+(n/1e3).toFixed(0)+'K':fmtUSD(n);
function pending24Meta(dateStr){
  if(dateStr<resetDateKey())return '<div class="cal-countdown-card"><strong class="cal-awaiting">awaiting sync</strong></div>';
  const closeTs=resetMidnightTs(addDays(dateStr,1))*1000;
  return `<div class="cal-countdown-card"><strong class="countdown" data-countdown="${closeTs}">${calendarTimeLeftLabel(closeTs)}</strong></div>`;
}
function calendarTimeLeftLabel(closeTs){
  const left=Math.max(0,closeTs-Date.now());
  const h=Math.floor(left/36e5),m=Math.floor((left%36e5)/6e4);
  return `${h}h ${String(m).padStart(2,'0')}m left`;
}
function updateCalendarCountdowns(){
  document.querySelectorAll('[data-countdown]').forEach(el=>{el.textContent=calendarTimeLeftLabel(+el.dataset.countdown);});
}
function calendarEarnHtml(dateStr,disp){
  if(CALMODE!=='day')return `<div class="cal-earn ${disp.span?'span':(disp.v?'':'zero')}">${disp.label}</div>`;
  const closed=isClosedDailyTotal(dateStr), total=CAL.eMap.get(dateStr)||0;
  const a=closed?calImpliedActivity(total):null;
  if(!closed)return `<div class="cal-dual pending-only" title="Time remaining until this ET daily total closes.">${pending24Meta(dateStr)}</div>`;
  return `<div class="cal-dual" title="Completed daily total only. Current/future dates stay pending until the day closes.">
    <div class="cal-money-row total"><span class="tz">Total</span><span class="money">+${fmtUSD(total)}</span></div>
    <div class="cal-flow-mini" title="Implied from 30D fee efficiency, not raw reported daily volume/OI">
      <div><b>${calMiniMoney(a.volume)}</b><span>Est Vol</span></div>
      <div><b>${calMiniMoney(a.oi)}</b><span>OI needed</span></div>
      <div class="burn"><b>${calMiniMoney(a.burn)}</b><span>Burn</span></div>
    </div>
  </div>`;
}
function calendarDisplay(dateStr){
  const base=cellVal(dateStr);
  if(CALMODE==='day'){
    const closed=isClosedDailyTotal(dateStr);
    return {...base,show:closed,label:closed&&base.v?('+'+fmtUSD(base.v)):'pending',span:false,end:closed};
  }
  if(CALMODE==='week'){
    const end=isSaturday(dateStr)&&dateStr<=CAL.last;
    return {...base,show:end,label:end?('+'+fmtUSD(base.v)):'',span:!end,end};
  }
  const me=monthEnd(dateStr);
  const end=dateStr===me&&dateStr<=CAL.last;
  return {...base,show:end,label:end?('+'+fmtUSD(base.v)):'',span:!end,end};
}
function renderHistoryMonths(){
  const box=$('#histMonths'); if(!box)return;
  const months=[];let m=SERIES[0].d.slice(0,7),end=SERIES[SERIES.length-1].d.slice(0,7);
  while(m<=end){months.push(m);m=ymAdd(m,1);}
  box.innerHTML=months.map(ym=>`<button type="button" class="${ym===CAL.month?'on':''}" data-m="${ym}">${monthName(ym).split(' ')[0]}</button>`).join('');
}
function paintCalendar(){
  const pendingCutoff=addDays(weekStart(resetDateKey()),13);
  if(CALMODE==='day'&&CAL.month>pendingCutoff.slice(0,7))CAL.month=pendingCutoff.slice(0,7);
  const first=CAL.month+'-01', monthLast=monthEnd(first);
  const end=CALMODE==='day'&&CAL.month===pendingCutoff.slice(0,7)&&pendingCutoff<monthLast?pendingCutoff:monthLast;
  const firstDow=new Date(first+'T00:00:00Z').getUTCDay();
  const start=addDays(first,-firstDow);
  const lastDow=new Date(end+'T00:00:00Z').getUTCDay();
  const finish=addDays(end,6-lastDow);
  let cells='',d=start;
  $('#calTitle').textContent=monthName(CAL.month);
  renderHistoryMonths();
  if(CALMODE!=='day'){
    const summaries=[];
    if(CALMODE==='week'){
      let ws=weekStart(first);
      while(ws<=end){
        const we=addDays(ws,6);
        if(we.slice(0,7)===CAL.month&&we<=CAL.last&&CAL.wk.has(ws))summaries.push({d:we,label:`Week ending ${we}`,v:CAL.wk.get(ws)||0});
        ws=addDays(ws,7);
      }
    }else if(CAL.mo.has(CAL.month)&&end<=CAL.last){
      summaries.push({d:end,label:`Month ending ${end}`,v:CAL.mo.get(CAL.month)||0});
    }
    $('#calGrid').className='cal-grid period-summary';
    $('#calGrid').innerHTML=summaries.length?summaries.map(x=>`<div class="cal-summary-card" data-d="${x.d}"><div class="cal-summary-period">${x.label}</div><div class="cal-summary-value">+${fmtUSD(x.v)}</div></div>`).join(''):'<div class="cal-summary-empty">No completed result for this period yet.</div>';
    autoSelect();
    return;
  }
  $('#calGrid').className='cal-grid';
  while(d<=finish){
    const inMonth=d.slice(0,7)===CAL.month;
    if(!inMonth){
      cells+=`<div class="cal-cell empty"><div class="cal-daytop"><span class="cal-num">${+d.slice(8,10)}</span></div></div>`;
      d=addDays(d,1);continue;
    }
    const dow=new Date(d+'T00:00:00Z').getUTCDay();
    const disp=calendarDisplay(d);
    const {v,max}=disp;
    const t=max>0?v/max:0;
    const events=macroByDate(d);
    const classes=['cal-cell',dow===0||dow===6?'weekend':'',d>CAL.last?'future':'',disp.span?'period-span':'',disp.end&&CALMODE!=='day'?'period-end':''].filter(Boolean).join(' ');
    const evHtml=events.map(e=>`<span class="ev ${e.kind}" title="${e.t} · ${e.name}">${e.tag}</span>`).join('');
    cells+=`<div class="${classes}" data-d="${d}" style="--h:${Math.round(t*78)}%">
      <div class="cal-fill"></div>
      <div class="cal-daytop"><span class="cal-num">${+d.slice(8,10)}</span><span class="cal-wd">${['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][dow]}</span></div>
      ${calendarEarnHtml(d,disp)}
      <div class="cal-events">${evHtml}</div>
    </div>`;
    d=addDays(d,1);
  }
  $('#calMonths').innerHTML='';
  $('#calGrid').innerHTML=cells;
  autoSelect();
}
function autoSelect(){
  const nodes=[...document.querySelectorAll('#calGrid [data-d]')];
  const visible=new Set(nodes.map(c=>c.dataset.d));
  const today=resetDateKey();
  let preferred=CAL.selectedDate&&visible.has(CAL.selectedDate)?CAL.selectedDate:null;
  if(!preferred&&CALMODE==='day'&&today.slice(0,7)===CAL.month&&visible.has(today))preferred=today;
  if(!preferred){
    const completed=nodes.map(c=>c.dataset.d).filter(d=>calendarDisplay(d).end);
    preferred=completed[completed.length-1]||nodes[nodes.length-1]?.dataset.d||CAL.month+'-01';
  }
  selectCell(preferred);
}
function updateSelectedDayProgress(){
  const bar=$('#calInspectorProgress');if(!bar||!CAL.selectedDate)return;
  let pct=0;
  if(CALMODE!=='day')pct=calendarDisplay(CAL.selectedDate).end?100:0;
  else if(isClosedDailyTotal(CAL.selectedDate))pct=100;
  else if(CAL.selectedDate===resetDateKey()){
    const start=resetMidnightTs(CAL.selectedDate)*1000;
    const end=resetMidnightTs(addDays(CAL.selectedDate,1))*1000;
    pct=Math.max(0,Math.min(100,(Date.now()-start)/(end-start)*100));
  }
  bar.style.width=pct.toFixed(2)+'%';
}
