/* ---------- referral copy ---------- */
function fallbackCopy(text){
  const ta=document.createElement('textarea');
  ta.value=text;
  ta.setAttribute('readonly','');
  ta.style.position='fixed';
  ta.style.top='-1000px';
  document.body.appendChild(ta);
  ta.select();
  try{document.execCommand('copy');}catch(_){}
  ta.remove();
}
function copyReferralCode(){
  const code='OMNIKOREAN';
  const btn=$('#refCopyBtn');
  const done=()=>{
    if(!btn)return;
    btn.classList.add('copied');
    btn.textContent='Copied';
    setTimeout(()=>{btn.classList.remove('copied');btn.textContent='Copy code';},1300);
  };
  if(navigator.clipboard?.writeText)navigator.clipboard.writeText(code).then(done).catch(()=>{fallbackCopy(code);done();});
  else{fallbackCopy(code);done();}
}
$('#refCopyBtn')?.addEventListener('click',copyReferralCode);
$('#refCodeCopy')?.addEventListener('click',copyReferralCode);

/* ---------- tabs ---------- */
const TABS=$('#tabs');
const TAB_ORDER_KEY='variationalTabOrder';
const VALID_TABS=['overview','daily-news','implied','historical','efficiency','biweekly','roadmap','points','comparison'];
const normalizeTabName=name=>{
  if(name==='charts'||name==='interval')return 'historical';
  if(name==='peers')return 'comparison';
  if(name==='spreads'||name==='implied-fees')return 'implied';
  if(name==='news'||name==='daily-var-news')return 'daily-news';
  if(name==='calendar'||name==='total-earnings'||name==='earnings')return 'overview';
  return name;
};
function saveTabOrder(){
  try{localStorage.setItem(TAB_ORDER_KEY,JSON.stringify([...TABS.children].map(b=>b.dataset.tab)));}catch(_){}
}
function applySavedTabOrder(){
  try{
    const saved=[...new Set(JSON.parse(localStorage.getItem(TAB_ORDER_KEY)||'[]').map(normalizeTabName))];
    if(!Array.isArray(saved))return;
    if(!saved.length){
      VALID_TABS.forEach(name=>{const btn=TABS.querySelector(`[data-tab="${name}"]`);if(btn)TABS.appendChild(btn);});
      return;
    }
    const oldImplied=saved.indexOf('implied');
    if(oldImplied>=0)saved.splice(oldImplied,1);
    const at=Math.max(0,saved.indexOf('overview'))+1;
    saved.splice(at,0,'implied');
    if(!saved.includes('daily-news'))saved.splice(at,0,'daily-news');
    const order=[...saved.filter(x=>VALID_TABS.includes(x)),...VALID_TABS.filter(x=>!saved.includes(x))];
    order.forEach(name=>{const btn=TABS.querySelector(`[data-tab="${name}"]`);if(btn)TABS.appendChild(btn);});
  }catch(_){}
}
function initDraggableTabs(){
  applySavedTabOrder();
  let dragged=null;
  [...TABS.children].forEach(btn=>{
    btn.draggable=true;
    btn.addEventListener('dragstart',e=>{
      dragged=btn;
      btn.classList.add('dragging');
      e.dataTransfer.effectAllowed='move';
      e.dataTransfer.setData('text/plain',btn.dataset.tab);
    });
    btn.addEventListener('dragend',()=>{
      btn.classList.remove('dragging');
      TABS.querySelectorAll('.drag-over').forEach(x=>x.classList.remove('drag-over'));
      dragged=null;
      saveTabOrder();
    });
    btn.addEventListener('dragover',e=>{
      e.preventDefault();
      if(!dragged||dragged===btn)return;
      btn.classList.add('drag-over');
      const before=e.clientX < btn.getBoundingClientRect().left + btn.offsetWidth/2;
      TABS.insertBefore(dragged,before?btn:btn.nextSibling);
    });
    btn.addEventListener('dragleave',()=>btn.classList.remove('drag-over'));
    btn.addEventListener('drop',e=>{
      e.preventDefault();
      TABS.querySelectorAll('.drag-over').forEach(x=>x.classList.remove('drag-over'));
      saveTabOrder();
    });
  });
}
function showTab(name,{push=true,scroll=true}={}){
  name=normalizeTabName(name);
  if(!VALID_TABS.includes(name))name='overview';
  document.querySelectorAll('[data-tg]').forEach(el=>{el.classList.toggle('tg-hide', el.dataset.tg!==name);});
  [...TABS.children].forEach(b=>{
    const on=b.dataset.tab===name;
    b.classList.toggle('on',on);
    b.setAttribute('aria-selected',on?'true':'false');
  });
  if(push)history.replaceState(null,'','#'+name);
  if(scroll)window.scrollTo({top:0,behavior:'smooth'});
  if(booted)requestAnimationFrame(render);
}
$('#bwTeaserLink')?.addEventListener('click',e=>{
  e.preventDefault();
  showTab('biweekly');
});
TABS.addEventListener('click',e=>{const b=e.target.closest('button');if(b)showTab(b.dataset.tab);});
TABS.addEventListener('keydown',e=>{
  if(!['ArrowLeft','ArrowRight','Home','End'].includes(e.key))return;
  e.preventDefault();
  const tabs=[...TABS.children], cur=tabs.findIndex(b=>b.classList.contains('on'));
  const next=e.key==='Home'?0:e.key==='End'?tabs.length-1:e.key==='ArrowRight'?(cur+1)%tabs.length:(cur-1+tabs.length)%tabs.length;
  tabs[next].focus();showTab(tabs[next].dataset.tab);
});

