/* ---------- donation address (hardcoded, never from fetched data) ----------
   EIP-55 checksum verified. The address is a literal constant; the displayed text
   is re-asserted from it on load and the copy button reads only this constant,
   so no API response or DOM tampering can substitute a different address. */
(function(){
  const DONATION_ADDR='0x054d5A7856D88Ed44C78D4027A555f5eC6E55f8d';
  const code=document.getElementById('donAddr');
  const btn=document.getElementById('donCopy');
  const scan=document.getElementById('donScan');
  if(code)code.textContent=DONATION_ADDR;
  if(scan)scan.href='https://arbiscan.io/address/'+DONATION_ADDR;
  const copyAddr=async()=>{
    try{if(navigator.clipboard&&navigator.clipboard.writeText){await navigator.clipboard.writeText(DONATION_ADDR);return true;}}catch(_){}
    try{const r=document.createRange();r.selectNode(code||document.getElementById('tipAddr'));const s=getSelection();s.removeAllRanges();s.addRange(r);const ok=document.execCommand('copy');s.removeAllRanges();return ok;}catch(_){return false;}
  };
  const legacyCopy=()=>{try{const r=document.createRange();r.selectNode(code);const s=getSelection();s.removeAllRanges();s.addRange(r);const ok=document.execCommand('copy');s.removeAllRanges();return ok;}catch(_){return false;}};
  /* cute top tip bar: short display, full-constant copy, remembers dismissal */
  const tip=document.getElementById('tipbar');
  if(tip){
    const ta=document.getElementById('tipAddr');
    if(ta)ta.textContent='0x054d…'+DONATION_ADDR.slice(-4);
    let dismissed=false; try{dismissed=localStorage.getItem('tipbarDismissed')==='1';}catch(_){}
    if(!dismissed)tip.hidden=false;
    const tc=document.getElementById('tipCopy');
    if(tc)tc.addEventListener('click',async()=>{
      const ok=await copyAddr();
      tc.textContent=ok?'Copied ♥':'Select below';tc.classList.toggle('ok',ok);
      setTimeout(()=>{tc.textContent='Copy';tc.classList.remove('ok');},1600);
    });
    const tx=document.getElementById('tipClose');
    if(tx)tx.addEventListener('click',()=>{tip.hidden=true;try{localStorage.setItem('tipbarDismissed','1');}catch(_){}});
  }
  if(btn)btn.addEventListener('click',async()=>{
    let ok=false;
    try{if(navigator.clipboard&&navigator.clipboard.writeText){await navigator.clipboard.writeText(DONATION_ADDR);ok=true;}}catch(_){}
    if(!ok)ok=legacyCopy();
    if(ok){btn.textContent='Copied';btn.classList.add('ok');setTimeout(()=>{btn.textContent='Copy address';btn.classList.remove('ok');},1600);}
    else{btn.textContent='Select and copy';setTimeout(()=>btn.textContent='Copy address',1600);}
  });
})();
